const KELLY_EMAIL_JS_API_JS =
  'import { store } from "./store.js";\n\nexport function toast(message) {\n  const old = document.querySelector(".toast");\n  if (old) old.remove();\n  const node = document.createElement("div");\n  node.className = "toast";\n  node.textContent = message;\n  document.body.appendChild(node);\n  setTimeout(() => node.remove(), 3200);\n}\n\nexport function withContextParams(path) {\n  const url = new URL(path, window.location.origin);\n  for (const key of ["demo", "lang"]) {\n    const value = store.params.get(key);\n    if (value && !url.searchParams.has(key)) url.searchParams.set(key, value);\n  }\n  return `${url.pathname}${url.search}`;\n}\n\nexport async function api(path, body = null) {\n  const url = withContextParams(path);\n  const res = await fetch(url, {\n    method: body ? "POST" : "GET",\n    headers: body ? { "Content-Type": "application/json" } : {},\n    body: body ? JSON.stringify(body) : null,\n  });\n  const data = await res.json();\n  if (!res.ok || data.error) throw new Error(data.error || `Request failed: ${res.status}`);\n  return data;\n}\n';

const KELLY_EMAIL_JS_FORMAT_JS =
  'import { optionalT, t } from "./i18n.js";\nimport { store } from "./store.js";\n\nexport function escapeHtml(value) {\n  return String(value || "")\n    .replaceAll("&", "&amp;")\n    .replaceAll("<", "&lt;")\n    .replaceAll(">", "&gt;")\n    .replaceAll(\'"\', "&quot;");\n}\n\nexport function shortSender(value) {\n  return (value || "").replace(/".*?"/g, "").replace(/\\s+/g, " ").trim() || t("unknown.sender");\n}\n\nexport function parseEmailAddresses(value) {\n  const results = [];\n  const pattern = /(?:"?([^"<,]*)"?\\s*)?<([^<>@\\s]+@[^<>\\s]+)>|([^<>,\\s]+@[^<>,\\s]+)/g;\n  let match;\n  while ((match = pattern.exec(value || ""))) {\n    results.push({\n      name: (match[1] || "").trim(),\n      address: (match[2] || match[3] || "").trim().toLowerCase(),\n    });\n  }\n  return results;\n}\n\nexport function accountForItem(item) {\n  const accounts = store.state.email_accounts?.accounts || [];\n  const itemAccount = item.account || item.account_id || item.mailbox_id || "";\n  return (\n    accounts.find((account) => account.mailbox_id === itemAccount) ||\n    accounts.find(\n      (account) =>\n        account.primary_email &&\n        String(item.to || "")\n          .toLowerCase()\n          .includes(String(account.primary_email).toLowerCase()),\n    ) ||\n    null\n  );\n}\n\nexport function accountLabel(item) {\n  const account = accountForItem(item);\n  if (!account) return item.account || item.account_id || item.mailbox_id || t("account.unknown");\n  return account.display_name || account.primary_email || account.mailbox_id || t("account.unknown");\n}\n\nexport function accountEmailLabel(item) {\n  const account = accountForItem(item);\n  return account?.primary_email || item.account || item.account_id || item.mailbox_id || t("account.unknown");\n}\n\nexport function replyIdentityForItem(item) {\n  const accounts = store.state.email_accounts?.accounts || [];\n  const recipients = new Set(parseEmailAddresses(item.to || "").map((address) => address.address));\n  const account = accountForItem(item);\n  const identities = accounts.flatMap((mailbox) =>\n    (mailbox.identities || []).map((identity) => ({ ...identity, mailbox })),\n  );\n  const direct = identities.find((entry) => recipients.has(String(entry.send_as_email || "").toLowerCase()));\n  if (direct) return direct;\n  const accountIdentity = (account?.identities || [])[0];\n  if (accountIdentity) return { ...accountIdentity, mailbox: account };\n  return identities[0] || null;\n}\n\nexport function replyIdentityLabel(item) {\n  const identity = replyIdentityForItem(item);\n  if (!identity) return t("identity.unknown");\n  const name = identity.display_name || identity.identity_id || t("identity.unknown");\n  const email = identity.send_as_email || identity.reply_to || "";\n  return email ? `${name} <${email}>` : name;\n}\n\nexport function sizeLabel(bytes) {\n  if (!bytes) return "0 B";\n  if (bytes < 1024) return `${bytes} B`;\n  if (bytes < 1024 * 1024) return `${Math.round(bytes / 1024)} KB`;\n  return `${(bytes / 1024 / 1024).toFixed(1)} MB`;\n}\n\nexport function isImage(att) {\n  return (att.content_type || "").startsWith("image/");\n}\n\nexport function isPdf(att) {\n  return att.content_type === "application/pdf" || /\\.pdf$/i.test(att.filename || "");\n}\n\nexport function attachmentHtml(att) {\n  const meta = `${escapeHtml(att.content_type || "file")} ${sizeLabel(att.size)}`;\n  const url = att.url ? escapeHtml(att.url) : "";\n  const link = url ? `<a href="${url}" target="_blank" rel="noopener">${escapeHtml(t("attachment.open"))}</a>` : "";\n  const preview =\n    url && isImage(att)\n      ? `<img class="attachment-preview-image" src="${url}" alt="${escapeHtml(att.filename)}" />`\n      : url && isPdf(att)\n        ? `<iframe class="attachment-preview-pdf" src="${url}" title="${escapeHtml(att.filename)}"></iframe>`\n        : "";\n  return `\n    <div class="attachment">\n      <div class="attachment-head">\n        <strong>${escapeHtml(att.filename)}</strong>\n        <span class="muted">${meta}</span>\n        ${link}\n      </div>\n      ${preview}\n    </div>`;\n}\n\nexport function badgeLabel(value) {\n  if (!value) return "";\n  const key = String(value);\n  return (\n    optionalT(`label.status.${key}`) ||\n    optionalT(`label.category.${key}`) ||\n    optionalT(`label.risk.${key}`) ||\n    key.replaceAll("_", " ")\n  );\n}\n\nexport function badge(text, extra = "") {\n  return `<span class="badge ${extra}">${escapeHtml(badgeLabel(text))}</span>`;\n}\n\nexport function actionLabel(action) {\n  const labels = {\n    archive: t("action_label.archive"),\n    mark_read: t("action_label.mark_read"),\n    send_reply: t("action_label.send_reply"),\n    draft_reply: t("action_label.draft_reply"),\n    keep_unread: t("action_label.keep_unread"),\n    review: t("action_label.review"),\n  };\n  return labels[action] || action || t("action_label.review");\n}\n\nexport function tooltipAttr(text) {\n  return `class="has-tooltip" data-tooltip="${escapeHtml(text)}" title="${escapeHtml(text)}"`;\n}\n\nexport function languageLabel(code) {\n  if (!code || code === "unknown") return t("language.unknown");\n  return t(`language.current.${code}`) || code;\n}\n';

const KELLY_EMAIL_JS_HELP_MODAL_JS =
  'import { escapeHtml } from "./format.js";\nimport { applyAccentTheme, renderLanguageSummary, renderThemeOptions, t } from "./i18n.js";\nimport { providerModeLabel, providerStatus, providerStatusText } from "./provider.js";\nimport { syncRoute } from "./router.js";\nimport { $, store } from "./store.js";\n\nfunction providerValue(...values) {\n  return values.map((value) => String(value || "").trim()).find(Boolean) || t("settings.not_configured");\n}\n\nfunction providerPair(primary, secondary) {\n  const left = String(primary || "").trim();\n  const right = String(secondary || "").trim();\n  if (left && right && left !== right) return `${left} / ${right}`;\n  return left || right || t("settings.not_configured");\n}\n\nfunction accountsCardsHtml() {\n  const payload = store.state.email_accounts || {};\n  const onboarding = payload.onboarding || {};\n  const accounts = payload.accounts || [];\n  const promptCard = `\n    <article class="account-help-card">\n      <div>\n        <strong>${escapeHtml(t("account.add_title"))}</strong>\n        <p>${escapeHtml(t("account.add_body"))}</p>\n      </div>\n      <pre><code>/kelly-email 帮我增加一个 email account：邮箱是 name@example.com，IMAP/SMTP 是 example.com，alias 有 support@example.com，用 Support 身份回复。请更新当前 provider config，但不要让我在聊天里贴密码。\n\n/kelly-email 给 main 账号增加 alias：hello@example.com，并新增一个 outbound identity：display name 是 Founder，send_as 是 founder@example.com。\n\n/kelly-email 测试当前 email account 配置，告诉我缺哪些 secret ref 或 Vault secret。</code></pre>\n    </article>\n  `;\n  if (!onboarding.configured) {\n    const missing = (onboarding.missing_env || [])\n      .map((name) => `<span class="env-pill warn">${escapeHtml(name)}</span>`)\n      .join("");\n    return `\n      ${promptCard}\n      <div class="onboarding-card compact">\n        <strong>${onboarding.state === "missing_secrets" ? escapeHtml(t("account.secrets_missing")) : escapeHtml(t("account.setup_required"))}</strong>\n        <p>${escapeHtml(onboarding.message || t("onboarding.default_message"))}</p>\n        ${missing ? `<div class="account-envs">${missing}</div>` : ""}\n      </div>\n    `;\n  }\n  if (!accounts.length) {\n    return `${promptCard}<div class="muted">${escapeHtml(t("account.no_accounts"))}</div>`;\n  }\n  const accountCards = accounts\n    .map((account) => {\n      const aliases = (account.aliases || []).map((alias) => `<span>${escapeHtml(alias)}</span>`).join("");\n      const identities = (account.identities || [])\n        .map(\n          (identity) => `\n      <div class="account-identity">\n        <span>${escapeHtml(identity.display_name || identity.identity_id)}</span>\n        <code>${escapeHtml(identity.send_as_email)}</code>\n      </div>\n    `,\n        )\n        .join("");\n      const imapOk = account.imap_env_configured ? "ok" : "warn";\n      const smtpOk = account.smtp_env_configured ? "ok" : "warn";\n      return `\n      <article class="account-card">\n        <div class="account-card-head">\n          <div>\n            <strong>${escapeHtml(account.display_name)}</strong>\n            <small>${escapeHtml(account.primary_email || account.mailbox_id)}</small>\n          </div>\n          <div class="account-envs">\n            <span class="env-pill ${imapOk}" title="${escapeHtml(account.imap_password_env)}">${escapeHtml(account.imap_env_configured ? t("account.imap_ready") : t("account.imap_missing"))}</span>\n            <span class="env-pill ${smtpOk}" title="${escapeHtml(account.smtp_password_env)}">${escapeHtml(account.smtp_env_configured ? t("account.smtp_ready") : t("account.smtp_missing"))}</span>\n          </div>\n        </div>\n        <div class="account-detail">\n          <div class="account-row"><span>IMAP</span><code>${escapeHtml(account.imap_host)}</code></div>\n          <div class="account-row"><span>SMTP</span><code>${escapeHtml(account.smtp_host || t("account.not_set"))}</code></div>\n          ${aliases ? `<div class="alias-list">${aliases}</div>` : ""}\n          ${identities ? `<div class="identity-list">${identities}</div>` : ""}\n        </div>\n      </article>\n    `;\n    })\n    .join("");\n  return `${promptCard}${accountCards}`;\n}\n\nfunction accountSummaryHtml() {\n  return accountsCardsHtml();\n}\n\nfunction valueOrMuted(value, fallback = t("settings.not_configured")) {\n  return value ? escapeHtml(value) : `<span class="muted">${escapeHtml(fallback)}</span>`;\n}\n\nfunction listPills(values, empty = t("settings.not_configured")) {\n  const rows = (values || []).filter(Boolean);\n  if (!rows.length) return `<span class="muted">${escapeHtml(empty)}</span>`;\n  return rows.map((value) => `<span class="settings-pill">${escapeHtml(value)}</span>`).join("");\n}\n\nfunction urlsHtml(urls = {}) {\n  const rows = Object.entries(urls || {}).filter(([, value]) => value);\n  if (!rows.length) return `<span class="muted">${escapeHtml(t("settings.no_urls"))}</span>`;\n  return rows\n    .map(\n      ([label, value]) => `\n    <div class="settings-row">\n      <span>${escapeHtml(label)}</span>\n      <a href="${escapeHtml(value)}" target="_blank" rel="noopener">${escapeHtml(value)}</a>\n    </div>\n  `,\n    )\n    .join("");\n}\n\nfunction profileSettingsHtml() {\n  const payload = store.state.email_accounts || {};\n  const profile = payload.profile || {};\n  const brands = payload.brands || [];\n  const contacts = (profile.contact_methods || []).map((method) => `${method.label}: ${method.value}`);\n  const brandHtml = brands.length\n    ? brands\n        .map(\n          (brand) => `\n      <article class="settings-card">\n        <div class="settings-card-title">${escapeHtml(brand.name || brand.brand_id || t("settings.brands"))}</div>\n        <p>${valueOrMuted(brand.description, t("settings.no_description"))}</p>\n        <div class="settings-list">\n          ${urlsHtml({\n            homepage: brand.homepage,\n            docs: brand.docs_url,\n            support: brand.support_url,\n            youtube: brand.youtube_url,\n          })}\n        </div>\n      </article>\n    `,\n        )\n        .join("")\n    : `<article class="settings-card"><div class="settings-card-title">${escapeHtml(t("settings.brands"))}</div><p class="muted">${escapeHtml(t("settings.no_brands"))}</p></article>`;\n  return `\n    <article class="settings-card">\n      <div class="settings-card-title">${escapeHtml(t("settings.operator"))}</div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.name"))}</span><strong>${valueOrMuted(profile.display_name)}</strong></div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.role"))}</span><strong>${valueOrMuted(profile.role)}</strong></div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.company"))}</span><strong>${valueOrMuted(profile.company)}</strong></div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.reply_as"))}</span><strong>${valueOrMuted(profile.default_reply_as)}</strong></div>\n      <div class="settings-pill-row">${listPills(profile.languages, t("settings.no_languages"))}</div>\n      <p>${valueOrMuted(profile.public_bio, t("settings.no_bio"))}</p>\n      <div class="settings-pill-row">${listPills(contacts, t("settings.no_contacts"))}</div>\n    </article>\n    ${brandHtml}\n  `;\n}\n\nfunction styleSettingsHtml() {\n  const payload = store.state.email_accounts || {};\n  const style = payload.style || {};\n  return `\n    <article class="settings-card">\n      <div class="settings-card-title">${escapeHtml(t("settings.voice"))}</div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.preset"))}</span><strong>${valueOrMuted(style.preset)}</strong></div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.language"))}</span><strong>${valueOrMuted(style.default_language, "auto")}</strong></div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.tone"))}</span><strong>${valueOrMuted(style.tone)}</strong></div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.audience"))}</span><strong>${valueOrMuted(style.audience)}</strong></div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.max_words"))}</span><strong>${valueOrMuted(style.max_reply_words)}</strong></div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.quote"))}</span><strong>${style.include_short_quote ? escapeHtml(t("settings.short_quote")) : escapeHtml(t("settings.no_quote"))}</strong></div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.signature"))}</span><strong>${valueOrMuted(style.signature_mode)}</strong></div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.signoff"))}</span><strong>${valueOrMuted(style.preferred_signoff)}</strong></div>\n      <p>${valueOrMuted(style.paragraph_style, t("settings.no_paragraph"))}</p>\n    </article>\n    <article class="settings-card">\n      <div class="settings-card-title">${escapeHtml(t("settings.reply_rules"))}</div>\n      <div class="settings-bullets">${(style.reply_rules || []).map((rule) => `<div>${escapeHtml(rule)}</div>`).join("") || `<span class="muted">${escapeHtml(t("settings.no_reply_rules"))}</span>`}</div>\n    </article>\n    <article class="settings-card">\n      <div class="settings-card-title">${escapeHtml(t("settings.cta_urls"))}</div>\n      <div class="settings-list">${urlsHtml(style.cta_urls || {})}</div>\n    </article>\n    <article class="settings-card">\n      <div class="settings-card-title">${escapeHtml(t("settings.official_urls"))}</div>\n      <div class="settings-list">${urlsHtml(payload.official_urls || {})}</div>\n    </article>\n  `;\n}\n\nfunction knowledgeSettingsHtml() {\n  const kb = store.state.email_accounts?.knowledge_base || {};\n  const sources = kb.sources || [];\n  const sourceHtml = sources.length\n    ? sources\n        .map(\n          (source) => `\n      <article class="settings-card">\n        <div class="settings-card-title">\n          ${escapeHtml(source.title || source.source_id || "Knowledge source")}\n          <span class="source-type">${escapeHtml(source.type || "source")}</span>\n        </div>\n        <div class="settings-list">\n          ${source.url ? `<div class="settings-row"><span>${escapeHtml(t("settings.url"))}</span><a href="${escapeHtml(source.url)}" target="_blank" rel="noopener">${escapeHtml(source.url)}</a></div>` : ""}\n          ${source.path ? `<div class="settings-row"><span>${escapeHtml(t("settings.path"))}</span><code>${escapeHtml(source.path)}</code></div>` : ""}\n          <div class="settings-pill-row">${listPills(source.use_for, t("settings.no_usage_tags"))}</div>\n        </div>\n      </article>\n    `,\n        )\n        .join("")\n    : `<article class="settings-card"><div class="settings-card-title">${escapeHtml(t("settings.sources"))}</div><p class="muted">${escapeHtml(t("settings.no_sources"))}</p></article>`;\n  return `\n    <article class="settings-card">\n      <div class="settings-card-title">${escapeHtml(t("settings.policy"))}</div>\n      <div class="settings-row"><span>${escapeHtml(t("settings.enabled"))}</span><strong>${kb.enabled ? escapeHtml(t("settings.yes")) : escapeHtml(t("settings.no"))}</strong></div>\n      <p>${valueOrMuted(kb.usage, t("settings.no_usage"))}</p>\n      <div class="settings-bullets">${(kb.facts || []).map((fact) => `<div>${escapeHtml(fact)}</div>`).join("") || `<span class="muted">${escapeHtml(t("settings.no_facts"))}</span>`}</div>\n    </article>\n    <article class="settings-card">\n      <div class="settings-card-title">${escapeHtml(t("settings.do_not_say"))}</div>\n      <div class="settings-bullets">${(kb.do_not_say || []).map((rule) => `<div>${escapeHtml(rule)}</div>`).join("") || `<span class="muted">${escapeHtml(t("settings.no_forbidden"))}</span>`}</div>\n    </article>\n    ${sourceHtml}\n  `;\n}\n\nexport function setHelpTab(name) {\n  document.querySelectorAll("[data-help-tab]").forEach((button) => {\n    button.classList.toggle("active", button.dataset.helpTab === name);\n  });\n  document.querySelectorAll("[data-help-panel]").forEach((panel) => {\n    panel.classList.toggle("active", panel.dataset.helpPanel === name);\n  });\n}\n\nexport function activeHelpTab() {\n  return document.querySelector("[data-help-tab].active")?.dataset.helpTab || "guide";\n}\n\nexport function isHelpOpen() {\n  return !$("helpModal")?.classList.contains("is-hidden");\n}\n\nexport function openHelp(tab = "guide") {\n  const modal = $("helpModal");\n  const batch = store.state.batch || {};\n  const onboarding = store.state.email_accounts?.onboarding || {};\n  const provider = providerStatus();\n  const connection = provider.connection || {};\n  $("helpBatchInfo").textContent = batch.batch_id\n    ? t("batch.info", { id: batch.batch_id, count: store.state.total_cached || 0, date: batch.generated_at || "" })\n    : t("batch.none");\n  $("helpDataReader").textContent = store.state.email_accounts?.data_reader || provider.provider || "local";\n  $("helpDataProvider").textContent = providerModeLabel(provider);\n  $("helpProviderStatus").textContent = providerStatusText(provider);\n  $("helpProviderFolder").textContent = providerValue(\n    provider.folder_slug,\n    connection.folder_slug,\n    connection.folder_node_id,\n  );\n  $("helpProviderBase").textContent = providerPair(\n    provider.base_id || connection.base_id,\n    provider.base_slug || connection.base_slug || connection.resolved_base_id,\n  );\n  $("helpProviderContactsBase").textContent = providerPair(\n    provider.contacts_base_id || connection.contacts_base_id,\n    provider.contacts_base_slug || connection.contacts_base_slug || connection.resolved_contacts_base_id,\n  );\n  $("helpProviderDrive").textContent = providerPair(\n    provider.drive_slug || connection.drive_slug,\n    provider.drive_id || connection.drive_id || connection.drive_node_id,\n  );\n  $("helpBatchPath").textContent = store.state.batch_path || t("files.no_batch");\n  $("helpContactsPath").textContent = store.state.contacts_path || t("files.no_contacts");\n  $("helpDecisionsPath").textContent = store.state.decisions_path || t("files.no_decisions");\n  $("helpConfigPath").textContent = onboarding.configured\n    ? store.state.email_accounts?.source || t("files.no_config")\n    : t("files.onboarding");\n  $("helpAccounts").innerHTML = accountSummaryHtml();\n  $("helpProfile").innerHTML = profileSettingsHtml();\n  $("helpStyle").innerHTML = styleSettingsHtml();\n  $("helpKnowledge").innerHTML = knowledgeSettingsHtml();\n  renderLanguageSummary();\n  renderThemeOptions();\n  applyAccentTheme();\n  setHelpTab(tab);\n  modal.classList.remove("is-hidden");\n  modal.setAttribute("aria-hidden", "false");\n  syncRoute({ push: true });\n}\n\nexport function closeHelp({ skipRoute = false } = {}) {\n  const modal = $("helpModal");\n  modal.classList.add("is-hidden");\n  modal.setAttribute("aria-hidden", "true");\n  if (!skipRoute) syncRoute({ push: true });\n}\n';

const KELLY_EMAIL_JS_I18N_JS =
  'import { I18N } from "../i18n/messages.js";\nimport { toast } from "./api.js";\nimport { escapeHtml } from "./format.js";\nimport {\n  $,\n  ACCENT_THEMES,\n  ACCENT_THEME_STORAGE_KEY,\n  LANGUAGE_OPTIONS,\n  LANGUAGE_STORAGE_KEY,\n  resolveAccentTheme,\n  store,\n} from "./store.js";\n\n// applyLockState/applyProviderGate/renderCounts/renderList/renderDetail all\n// live in modules that import from here (i18n applies to their markup), so\n// setLanguageMode reaches them lazily to avoid a hard circular import at the\n// top level. See main.js, which wires the real functions in after every\n// module has finished loading.\nconst rerenderHooks = { onLanguageChange: () => {} };\nexport function onLanguageChange(fn) {\n  rerenderHooks.onLanguageChange = fn;\n}\n\nexport function template(value, params = {}) {\n  return String(value || "").replace(/\\{(\\w+)\\}/g, (_, key) => params[key] ?? "");\n}\n\nexport function t(key, params = {}) {\n  return template(I18N[store.uiLanguage]?.[key] || I18N.en[key] || key, params);\n}\n\nexport function optionalT(key) {\n  return I18N[store.uiLanguage]?.[key] || I18N.en[key] || "";\n}\n\nfunction browserLanguage() {\n  const languages = navigator.languages?.length ? navigator.languages : [navigator.language || "en"];\n  return languages.some((lang) => String(lang).toLowerCase().startsWith("zh")) ? "zh-CN" : "en";\n}\n\nfunction resolveLanguage() {\n  if (!["auto", "en", "zh-CN"].includes(store.languageMode)) store.languageMode = "auto";\n  return store.languageMode === "auto" ? browserLanguage() : store.languageMode;\n}\n\nfunction languageSwitcherHtml(container) {\n  const name = container.dataset.languageName || "uiLanguage";\n  const title =\n    container.dataset.languageTitle === "true"\n      ? `<span data-language-title-label>${escapeHtml(t("language.title"))}</span>`\n      : "";\n  const options = LANGUAGE_OPTIONS.map(\n    (option) => `\n      <label data-ui-language-option>\n        <input\n          type="radio"\n          name="${escapeHtml(name)}"\n          value="${escapeHtml(option.value)}"\n          data-ui-language\n          ${option.value === store.languageMode ? "checked" : ""}\n        />\n        <span data-language-label-key="${escapeHtml(option.labelKey)}">${escapeHtml(t(option.labelKey))}</span>\n      </label>\n    `,\n  ).join("");\n  return `${title}${options}`;\n}\n\nexport function renderLanguageSwitchers() {\n  document.querySelectorAll("[data-language-switcher]").forEach((container) => {\n    if (container.dataset.languageSwitcherReady !== "true") {\n      container.innerHTML = languageSwitcherHtml(container);\n      container.dataset.languageSwitcherReady = "true";\n    }\n    container.querySelectorAll("[data-ui-language]").forEach((input) => {\n      input.checked = input.value === store.languageMode;\n    });\n    const title = container.querySelector("[data-language-title-label]");\n    if (title) title.textContent = t("language.title");\n    container.querySelectorAll("[data-language-label-key]").forEach((label) => {\n      label.textContent = t(label.dataset.languageLabelKey);\n    });\n  });\n}\n\nexport function renderLanguageSummary() {\n  const node = $("languageSummary");\n  if (!node) return;\n  const current = t(`language.current.${store.uiLanguage}`);\n  node.textContent =\n    store.languageMode === "auto"\n      ? t("language.summary.auto", { language: current })\n      : t("language.summary.fixed", { language: current });\n}\n\nexport function setLanguageMode(value) {\n  const nextMode = ["auto", "en", "zh-CN"].includes(value) ? value : "auto";\n  if (nextMode === store.languageMode) {\n    renderLanguageSwitchers();\n    return;\n  }\n  store.languageMode = nextMode;\n  localStorage.setItem(LANGUAGE_STORAGE_KEY, store.languageMode);\n  applyTranslations();\n  rerenderHooks.onLanguageChange();\n  toast(t("language.saved"));\n}\n\nexport function accentThemeLabel(id = store.accentTheme) {\n  return t(`theme.${resolveAccentTheme(id)}`);\n}\n\nexport function renderThemeSummary() {\n  const node = $("themeSummary");\n  if (!node) return;\n  node.textContent = t("theme.summary", { theme: accentThemeLabel() });\n}\n\nexport function renderThemeOptions() {\n  const node = $("themeOptions");\n  if (!node) return;\n  node.innerHTML = ACCENT_THEMES.map(\n    (theme) => `\n      <label class="theme-option" style="--swatch: ${theme.color}; --swatch-check: ${theme.check || "#ffffff"}">\n        <input type="radio" name="accentTheme" value="${theme.id}" ${theme.id === store.accentTheme ? "checked" : ""} />\n        <span class="theme-swatch" aria-hidden="true"></span>\n        <span>${escapeHtml(accentThemeLabel(theme.id))}</span>\n      </label>\n    `,\n  ).join("");\n  node.querySelectorAll(\'input[name="accentTheme"]\').forEach((input) => {\n    input.onchange = () => setAccentTheme(input.value);\n  });\n}\n\nexport function applyAccentTheme() {\n  store.accentTheme = resolveAccentTheme(store.accentTheme);\n  document.documentElement.dataset.accentTheme = store.accentTheme;\n  document.querySelectorAll(\'input[name="accentTheme"]\').forEach((input) => {\n    input.checked = input.value === store.accentTheme;\n  });\n  renderThemeSummary();\n}\n\nexport function setAccentTheme(value) {\n  store.accentTheme = resolveAccentTheme(value);\n  localStorage.setItem(ACCENT_THEME_STORAGE_KEY, store.accentTheme);\n  applyAccentTheme();\n  toast(t("theme.saved", { theme: accentThemeLabel() }));\n}\n\nexport function applyTranslations() {\n  store.uiLanguage = resolveLanguage();\n  document.documentElement.lang = store.uiLanguage === "zh-CN" ? "zh-CN" : "en";\n  document.querySelectorAll("[data-i18n]").forEach((node) => {\n    node.textContent = t(node.dataset.i18n);\n  });\n  document.querySelectorAll("option[data-i18n]").forEach((node) => {\n    node.textContent = t(node.dataset.i18n);\n  });\n  document.querySelectorAll("[data-i18n-html]").forEach((node) => {\n    node.innerHTML = t(node.dataset.i18nHtml);\n  });\n  document.querySelectorAll("[data-i18n-placeholder]").forEach((node) => {\n    node.placeholder = t(node.dataset.i18nPlaceholder);\n  });\n  document.querySelectorAll("[data-i18n-tooltip]").forEach((node) => {\n    const text = t(node.dataset.i18nTooltip);\n    node.dataset.tooltip = text;\n    node.title = text;\n  });\n  document.querySelectorAll("[data-i18n-aria-label]").forEach((node) => {\n    node.setAttribute("aria-label", t(node.dataset.i18nAriaLabel));\n  });\n  renderLanguageSwitchers();\n  renderThemeOptions();\n  renderLanguageSummary();\n  applyAccentTheme();\n}\n';

const KELLY_EMAIL_JS_LIST_DETAIL_JS =
  'import { api, toast } from "./api.js";\nimport {\n  accountEmailLabel,\n  accountLabel,\n  actionLabel,\n  attachmentHtml,\n  badge,\n  escapeHtml,\n  languageLabel,\n  replyIdentityLabel,\n  shortSender,\n  tooltipAttr,\n} from "./format.js";\nimport { t, template } from "./i18n.js";\nimport { setupNeeded } from "./provider.js";\nimport {\n  applyRouteFromHash,\n  hashHasSelectedMessage,\n  navigateTo,\n  registerRouterHooks,\n  routeFor,\n  syncRoute,\n} from "./router.js";\nimport {\n  applyLockState,\n  attachHtmlPreviewAutoResize,\n  captureScrollState,\n  closeDetailActionMenu,\n  isEditing,\n  isLocked,\n  isMobileLayout,\n  pollLock,\n  restoreScrollState,\n  setMobileDetailOpen,\n} from "./shell.js";\nimport { $, store } from "./store.js";\n\nfunction countFor(name) {\n  if (name === "all") return store.state.total_cached || 0;\n  return store.state.counts[name] || 0;\n}\n\nfunction modeLabel(name = store.mode) {\n  return t(`filter.${name}`);\n}\n\nexport function renderMobileTopbar() {\n  const title = $("mobileViewTitle");\n  const meta = $("mobileViewMeta");\n  if (!title || !meta) return;\n  title.textContent =\n    store.selectedId && store.mobileDetailOpen ? selectedItem()?.subject || t("empty.select_message") : modeLabel();\n  meta.textContent = t("list.items", { count: store.state.items?.length || 0 });\n}\n\nexport function renderCounts() {\n  ["all", "needs_review", "approved", "done", "blocked"].forEach((name) => {\n    const el = $(`count-${name}`);\n    if (el) el.textContent = countFor(name);\n  });\n  const humanNeeds = $("count-human-needs_review");\n  const humanApproved = $("count-human-approved");\n  const humanBlocked = $("count-human-blocked");\n  if (humanNeeds) humanNeeds.textContent = countFor("needs_review");\n  if (humanApproved) humanApproved.textContent = countFor("approved");\n  if (humanBlocked) humanBlocked.textContent = countFor("blocked");\n  renderMobileTopbar();\n}\n\nexport function renderBulkActions() {\n  const bar = $("bulkActions");\n  const selected = $("selectedCount");\n  if (!bar || !selected) return;\n  const count = store.checked.size;\n  bar.classList.toggle("is-hidden", count === 0);\n  selected.textContent = t("list.selected", { count });\n  const bulkSelect = $("bulkDecisionSelect");\n  if (bulkSelect) bulkSelect.value = "";\n}\n\nfunction decisionLabel(item) {\n  const action = item.decision?.action;\n  if (!action) return "";\n  if (action === "review" || action === "needs_review") return badge(t("badge.review_requested"), "review");\n  if (action === "draft_reply") return badge(t("badge.approved_draft"), "decided");\n  if (action === "mark_read") return badge(t("badge.approved_mark_read"), "decided");\n  if (action === "send_reply") return badge(t("badge.approved_send"), "decided");\n  if (action === "no_action") return badge(t("badge.no_action"), "done");\n  return badge(t("badge.approved_action", { action: actionLabel(action) }), "decided");\n}\n\nfunction executionLabel(item) {\n  const execution = item.execution || {};\n  if (execution.status === "executed")\n    return badge(t("badge.executed", { action: actionLabel(execution.action) }), "executed");\n  if (execution.status === "blocked") return badge(t("badge.blocked"), "blocked");\n  return "";\n}\n\nfunction reviewBriefFor(item) {\n  const brief = item.review_brief || {};\n  const localized = brief.i18n?.[store.uiLanguage] || brief.i18n?.[brief.user_language] || brief.i18n?.en || null;\n  const background =\n    localized?.background ||\n    brief.background ||\n    t("review.background.default", {\n      from: item.from || t("unknown.sender"),\n      subject: item.subject || t("unknown.subject"),\n      summary: item.summary || "",\n    });\n  const why =\n    localized?.why_review ||\n    (store.uiLanguage === "zh-CN" ? brief.why_review || item.reason : "") ||\n    t("review.why.default");\n  let recommendation =\n    localized?.recommendation ||\n    (store.uiLanguage === "zh-CN" ? brief.recommendation : "") ||\n    t("review.recommend.default");\n  const category = item.category || "";\n  const risks = new Set(item.risk || []);\n  if (!localized?.recommendation && !(store.uiLanguage === "zh-CN" && brief.recommendation)) {\n    if (category === "money" || risks.has("money")) {\n      recommendation = t("review.recommend.money");\n    } else if (category === "course_feedback") {\n      recommendation = t("review.recommend.course");\n    } else if (category.includes("security") || risks.has("security")) {\n      recommendation = t("review.recommend.security");\n    } else if (category === "partnership") {\n      recommendation = t("review.recommend.partnership");\n    } else if (category === "customer") {\n      recommendation = t("review.recommend.customer");\n    } else if ((item.attachments || []).length) {\n      recommendation = t("review.recommend.attachments");\n    }\n  }\n  return { background, why, recommendation };\n}\n\nfunction suggestedReplyFor(item) {\n  return String(item.draft || item.suggested_reply || item.review_brief?.suggested_reply || "").trim();\n}\n\nfunction primaryActionFor(item) {\n  if (item.status === "drafted" || item.proposed_action === "send_reply" || item.decision?.action === "send_reply") {\n    return {\n      id: "approveSend",\n      action: "approve_send",\n      label: t("action.approve_send"),\n      tooltip: t("detail.send.tooltip"),\n    };\n  }\n  if (item.proposed_action === "archive") {\n    return {\n      id: "approveArchive",\n      action: "approve_archive",\n      label: t("action.approve_archive"),\n      tooltip: t("detail.archive.tooltip"),\n    };\n  }\n  if (item.proposed_action === "mark_read" || item.proposed_action === "keep_unread") {\n    return {\n      id: "approveRead",\n      action: "approve_mark_read",\n      label: t("action.approve_read"),\n      tooltip: t("detail.read.tooltip"),\n    };\n  }\n  if (item.proposed_action === "draft_reply") {\n    return {\n      id: "draftReply",\n      action: "draft_reply",\n      label: t("action.draft_reply"),\n      tooltip: t("detail.draft.tooltip"),\n    };\n  }\n  return {\n    id: "approveProposed",\n    action: "approve_proposed",\n    label: t("action.approve_plan"),\n    tooltip: t("detail.approve.tooltip"),\n  };\n}\n\nfunction planBadge(item) {\n  const action = item.proposed_action || "review";\n  if (action === "review") return badge(t("action_label.review"), "review");\n  return badge(t("badge.suggested", { action: actionLabel(action) }));\n}\n\nfunction emailBodySectionsHtml(item) {\n  const original = item.body_original || item.body || "";\n  const translation = item.body_translation || item.translated_body || "";\n  const sourceLanguage = item.body_original_language || item.source_language || "";\n  const translationLanguage =\n    item.body_translation_language || item.translation_language || item.review_brief?.user_language || "";\n  const originalLabel =\n    sourceLanguage && sourceLanguage !== "unknown"\n      ? `${t("detail.original_text")} · ${languageLabel(sourceLanguage)}`\n      : t("detail.original_text");\n  const translationHtml = translation\n    ? `\n      <div class="section-title">${escapeHtml(t("detail.translation_text"))} · ${escapeHtml(languageLabel(translationLanguage))}</div>\n      <div class="body-box translated-body">${escapeHtml(translation)}</div>\n    `\n    : `<div class="translation-empty">${escapeHtml(t("detail.translation_empty"))}</div>`;\n  return `\n    <div class="section-title">${escapeHtml(originalLabel)}</div>\n    <div class="body-box">${escapeHtml(original)}</div>\n    ${translationHtml}\n  `;\n}\n\nfunction reviewBriefHtml(item) {\n  const needs = item.status === "needs_review" || ["needs_review", "revise", "review"].includes(item.decision?.action);\n  if (!needs) return "";\n  const brief = reviewBriefFor(item);\n  const title = item.review_ref ? `${t("detail.suggestion")} · ${item.review_ref}` : t("detail.suggestion");\n  return `\n    <div class="review-advice">\n      <div class="review-advice-title">${escapeHtml(title)}</div>\n      <dl>\n        <dt>${escapeHtml(t("detail.background"))}</dt>\n        <dd>${escapeHtml(brief.background)}</dd>\n        <dt>${escapeHtml(t("detail.why_review"))}</dt>\n        <dd>${escapeHtml(brief.why)}</dd>\n        <dt>${escapeHtml(t("detail.recommendation"))}</dt>\n        <dd>${escapeHtml(brief.recommendation)}</dd>\n      </dl>\n    </div>\n  `;\n}\n\nfunction rowHtml(item) {\n  const risks = (item.risk || []).map((risk) => badge(risk, risk)).join("");\n  const checkedAttr = store.checked.has(item.id) ? "checked" : "";\n  const reviewRef = item.review_ref ? `<span class="review-ref">${escapeHtml(item.review_ref)}</span>` : "";\n  return `\n    <div class="message-row ${store.selectedId === item.id ? "selected" : ""}" data-id="${escapeHtml(item.id)}">\n      <div><input type="checkbox" class="row-check" data-id="${escapeHtml(item.id)}" ${checkedAttr}></div>\n      <div>\n        <div class="row-top">\n          <div class="sender-line">${reviewRef}<span class="sender">${escapeHtml(shortSender(item.from))}</span></div>\n          <div class="date">${escapeHtml(item.uid)}</div>\n        </div>\n        <div class="row-account">\n          <span>${escapeHtml(t("list.account"))}</span>\n          <strong>${escapeHtml(accountLabel(item))}</strong>\n        </div>\n        <div class="subject">${escapeHtml(item.subject)}</div>\n        <div class="summary">${escapeHtml(item.summary)}</div>\n        <div class="badges">\n          ${badge(item.status || t("badge.new"), item.status || "")}\n          ${badge(item.category || t("badge.other"))}\n          ${planBadge(item)}\n          ${risks}\n          ${decisionLabel(item)}\n          ${executionLabel(item)}\n        </div>\n      </div>\n    </div>`;\n}\n\nexport function renderList() {\n  if (setupNeeded()) {\n    $("messageList").innerHTML = `<div class="empty-detail">${escapeHtml(t("setup.list_empty"))}</div>`;\n    $("listCount").textContent = t("list.setup_required");\n    return;\n  }\n  if (!store.selectedId || !store.state.items.some((item) => item.id === store.selectedId)) {\n    if (isMobileLayout() && !hashHasSelectedMessage()) {\n      store.selectedId = null;\n      setMobileDetailOpen(false);\n    } else {\n      store.selectedId = store.state.items[0]?.id || null;\n      syncRoute({ push: false });\n    }\n  }\n  $("messageList").innerHTML =\n    store.state.items.map(rowHtml).join("") || `<div class="empty-detail">${escapeHtml(t("list.no_items"))}</div>`;\n  $("listCount").textContent = t("list.items", { count: store.state.items.length });\n  renderMobileTopbar();\n  document.querySelectorAll(".message-row").forEach((row) => {\n    row.addEventListener("click", (event) => {\n      if (isLocked()) return;\n      if (event.target.classList.contains("row-check")) return;\n      if (isMobileLayout()) setMobileDetailOpen(true);\n      navigateTo({ selectedId: row.dataset.id });\n    });\n  });\n  document.querySelectorAll(".row-check").forEach((box) => {\n    box.addEventListener("change", () => {\n      if (isLocked()) {\n        box.checked = store.checked.has(box.dataset.id);\n        return;\n      }\n      if (box.checked) store.checked.add(box.dataset.id);\n      else store.checked.delete(box.dataset.id);\n      renderBulkActions();\n    });\n  });\n  renderBulkActions();\n}\n\nexport function onboardingHtml() {\n  const onboarding = store.state.email_accounts?.onboarding || {};\n  const missing = (onboarding.missing_env || [])\n    .map((name) => `<span class="env-pill warn">${escapeHtml(name)}</span>`)\n    .join("");\n  return `\n    <div class="onboarding-card">\n      <strong>${onboarding.state === "missing_secrets" ? escapeHtml(t("onboarding.add_secrets")) : escapeHtml(t("onboarding.setup"))}</strong>\n      <p>${escapeHtml(onboarding.message || t("onboarding.default_message"))}</p>\n      <ol>\n        <li>${template(escapeHtml(t("onboarding.copy")), { path: `<code>${escapeHtml(onboarding.example_config || ".agents/skills/kelly-email/config.example.json")}</code>` })}</li>\n        <li>${template(escapeHtml(t("onboarding.save_as")), { path: `<code>${escapeHtml(onboarding.recommended_config || "~/.config/kelly-email/config.json")}</code>` })}</li>\n        <li>${escapeHtml(t("onboarding.fill"))}</li>\n        <li>${template(escapeHtml(t("onboarding.env")), { path: `<code>${escapeHtml(onboarding.recommended_env || "~/.config/kelly-email/.env")}</code>` })}</li>\n        <li>${escapeHtml(t("onboarding.test"))}</li>\n      </ol>\n      ${missing ? `<div class="account-envs">${missing}</div>` : ""}\n    </div>\n  `;\n}\n\nexport function selectedItem() {\n  return store.state.items.find((item) => item.id === store.selectedId);\n}\n\nexport function renderDetail() {\n  const backButton = `<button class="back-to-list" type="button">${escapeHtml(t("detail.back_to_list"))}</button>`;\n  if (setupNeeded()) {\n    $("detailPanel").innerHTML = `${backButton}<div class="empty-detail">${escapeHtml(t("setup.detail_empty"))}</div>`;\n    renderMobileTopbar();\n    return;\n  }\n  const item = selectedItem();\n  if (!item) {\n    $("detailPanel").innerHTML =\n      `${backButton}<div class="empty-detail">${escapeHtml(t("empty.select_message"))}</div>`;\n    renderMobileTopbar();\n    return;\n  }\n  const attachments = (item.attachments || []).map(attachmentHtml).join("");\n  const htmlPreview = (item.html || "").trim()\n    ? `<iframe class="html-preview" sandbox srcdoc="${escapeHtml(item.html)}"></iframe>`\n    : `<div class="body-box muted">${escapeHtml(t("detail.no_html"))}</div>`;\n  const risks = (item.risk || []).map((risk) => badge(risk, risk)).join("");\n  const suggestedReply = suggestedReplyFor(item);\n  const showDraft = Boolean(suggestedReply) || item.status === "drafted" || item.decision?.action === "send_reply";\n  const draftSection = showDraft\n    ? `\n    <div class="section-title">${escapeHtml(t("detail.suggested_reply"))}</div>\n    <textarea id="draftText" class="draft-box" placeholder="${escapeHtml(t("detail.suggested_reply.placeholder"))}">${escapeHtml(suggestedReply)}</textarea>\n  `\n    : `<textarea id="draftText" class="draft-box is-hidden">${escapeHtml(item.draft || "")}</textarea>`;\n  const reviewMeta = item.review_ref\n    ? `<strong>${escapeHtml(t("detail.review"))}</strong><div><span class="review-ref detail-review-ref">${escapeHtml(item.review_ref)}</span></div>`\n    : "";\n  const primaryAction = primaryActionFor(item);\n  const menuActions = [\n    ["draftReply", "draft_reply", t("action.draft_reply"), t("detail.draft.tooltip")],\n    ["approveArchive", "approve_archive", t("action.approve_archive"), t("detail.archive.tooltip")],\n    ["approveRead", "approve_mark_read", t("action.approve_read"), t("detail.read.tooltip")],\n    ["approveSend", "approve_send", t("action.approve_send"), t("detail.send.tooltip")],\n    ["markReview", "needs_review", t("action.needs_review"), t("detail.review.tooltip")],\n    ["noAction", "no_action", t("action.no_action"), t("detail.no_action.tooltip")],\n  ].filter(([id]) => id !== primaryAction.id);\n  const actionBar = `\n    <div class="detail-actions detail-actions-top">\n      <div class="action-cluster">\n        <button id="primaryDetailAction" class="detail-primary-action primary has-tooltip" data-tooltip="${escapeHtml(primaryAction.tooltip)}" title="${escapeHtml(primaryAction.tooltip)}">${escapeHtml(primaryAction.label)}</button>\n        <button\n          id="detailActionMenuToggle"\n          class="detail-more-action"\n          type="button"\n          aria-haspopup="menu"\n          aria-expanded="false"\n          aria-label="${escapeHtml(t("action.more"))}"\n          title="${escapeHtml(t("action.more"))}"\n        >${escapeHtml(t("action.more"))}</button>\n        <div id="detailActionMenu" class="detail-action-menu" role="menu">\n          ${menuActions\n            .map(\n              ([id, action, label, tooltip], index) => `\n            ${index === 4 ? `<span class="detail-action-separator" aria-hidden="true"></span>` : ""}\n            <button id="${escapeHtml(id)}" type="button" role="menuitem" data-action="${escapeHtml(action)}" ${tooltipAttr(tooltip)}>${escapeHtml(label)}</button>\n          `,\n            )\n            .join("")}\n        </div>\n      </div>\n    </div>\n  `;\n  $("detailPanel").innerHTML = `\n    ${backButton}\n    ${actionBar}\n    <div class="detail-title">${escapeHtml(item.subject)}</div>\n    <div class="detail-meta">\n      ${reviewMeta}\n      <strong>${escapeHtml(t("detail.source_account"))}</strong><div>${escapeHtml(accountLabel(item))} <span class="muted">· ${escapeHtml(accountEmailLabel(item))}</span></div>\n      <strong>${escapeHtml(t("detail.reply_identity"))}</strong><div>${escapeHtml(replyIdentityLabel(item))}</div>\n      <strong>${escapeHtml(t("detail.from"))}</strong><div>${escapeHtml(item.from)}</div>\n      <strong>${escapeHtml(t("detail.to"))}</strong><div>${escapeHtml(item.to)}</div>\n      <strong>${escapeHtml(t("detail.date"))}</strong><div>${escapeHtml(item.date)}</div>\n      <strong>${escapeHtml(t("detail.status"))}</strong><div>${badge(item.status, item.status)} ${badge(item.category)} ${risks} ${decisionLabel(item)} ${executionLabel(item)}</div>\n      <strong>${escapeHtml(t("detail.next"))}</strong><div>${escapeHtml(actionLabel(item.proposed_action))} · ${escapeHtml(item.reason)}</div>\n    </div>\n    ${reviewBriefHtml(item)}\n    ${draftSection}\n    <div class="section-title">${escapeHtml(t("detail.html_email"))}</div>\n    ${htmlPreview}\n    <div class="section-title">${escapeHtml(t("detail.attachments"))}</div>\n    <div class="attachment-list">${attachments || `<span class="muted">${escapeHtml(t("detail.no_attachments"))}</span>`}</div>\n    <div class="section-title">${escapeHtml(t("detail.review_note"))}</div>\n    <textarea id="commentText" class="comment-box" placeholder="${escapeHtml(t("detail.comment.placeholder"))}">${escapeHtml(item.user_comment || "")}</textarea>\n    <div class="detail-actions">\n      <button id="saveDetail" class="has-tooltip" data-tooltip="${escapeHtml(t("detail.save.tooltip"))}" title="${escapeHtml(t("detail.save.tooltip"))}">${escapeHtml(t("action.save_note"))}</button>\n    </div>\n    ${emailBodySectionsHtml(item)}\n  `;\n  renderMobileTopbar();\n  attachHtmlPreviewAutoResize();\n  applyLockState();\n  closeDetailActionMenu();\n  $("primaryDetailAction").onclick = () => decide(primaryAction.action, [item.id]);\n  $("detailActionMenuToggle").onclick = (event) => {\n    event.stopPropagation();\n    if (isLocked()) return toast(t("lock.processing"));\n    store.openActionMenu = !store.openActionMenu;\n    $("detailActionMenu").classList.toggle("is-open", store.openActionMenu);\n    $("detailActionMenuToggle").setAttribute("aria-expanded", String(store.openActionMenu));\n  };\n  menuActions.forEach(([id, action]) => {\n    const button = $(id);\n    if (!button) return;\n    button.onclick = () => {\n      closeDetailActionMenu();\n      decide(action, [item.id]);\n    };\n  });\n  $("saveDetail").onclick = async () => {\n    if (isLocked()) return toast(t("lock.processing"));\n    await api("/api/detail", {\n      id: item.id,\n      draft: $("draftText").value,\n      suggested_reply: $("draftText").value,\n      comment: $("commentText").value,\n    });\n    toast(t("toast.saved_detail"));\n    await refresh({ preserveScroll: false });\n    store.selectedId = item.id;\n    renderDetail();\n  };\n}\n\nexport async function refresh({ preserveScroll = true } = {}) {\n  if (isEditing()) return pollLock();\n  applyRouteFromHash();\n  const scrollState = preserveScroll ? captureScrollState() : null;\n  const q = encodeURIComponent($("searchInput").value || "");\n  if (store.mode === "to_approve") store.mode = "approved";\n  store.state = await api(`/api/state?mode=${store.mode}&q=${q}`);\n  renderCounts();\n  renderList();\n  renderDetail();\n  applyLockState();\n  if (store.routeNeedsReplace) {\n    history.replaceState(null, "", `#${routeFor()}`);\n    store.routeNeedsReplace = false;\n  }\n  if (scrollState) requestAnimationFrame(() => restoreScrollState(scrollState));\n}\n\nexport async function decide(action, ids = null) {\n  if (isLocked()) return toast(t("lock.processing"));\n  const isSingleDetailAction = Array.isArray(ids) && ids.length === 1;\n  const list = isSingleDetailAction ? ids : Array.from(store.checked);\n  if (!list.length) return toast(t("toast.select_one"));\n  const item = isSingleDetailAction ? selectedItem() : null;\n  const comment = item ? $("commentText")?.value || "" : "";\n  const payload = { ids: list, action };\n  if (item) {\n    payload.comment = comment;\n    payload.draft = $("draftText")?.value || item.draft || "";\n    payload.suggested_reply = $("draftText")?.value || item.suggested_reply || "";\n  }\n  const data = await api("/api/decision", payload);\n  list.forEach((id) => store.checked.delete(id));\n  toast(t("toast.saved_count", { count: data.changed.length }));\n  await refresh({ preserveScroll: false });\n}\n\n// router.js needs refresh/renderList/renderDetail (registered below) and this\n// module needs navigateTo/syncRoute from router.js — a real two-way edge, but\n// safe in ESM since every use on both sides happens inside function bodies,\n// never at module-evaluation time.\nregisterRouterHooks({\n  refresh,\n  renderList,\n  renderDetail,\n});\n';

const KELLY_EMAIL_JS_PROVIDER_JS =
  'import { t } from "./i18n.js";\nimport { store } from "./store.js";\n\nexport function providerStatus() {\n  const status = store.state.provider_status || {};\n  const provider =\n    status.provider || store.state.email_accounts?.data_provider || store.state.email_accounts?.data_reader || "local";\n  return {\n    ...status,\n    provider,\n    mode: status.mode || provider,\n  };\n}\n\nexport function providerReady() {\n  return providerStatus().ok !== false;\n}\n\nexport function onboardingReady() {\n  return store.state.email_accounts?.onboarding?.configured !== false;\n}\n\nexport function setupNeeded() {\n  return !providerReady() || !onboardingReady();\n}\n\nexport function providerModeLabel(status = providerStatus()) {\n  const provider = status.provider || "local";\n  const mode = status.mode || provider;\n  return provider === mode ? provider : `${provider} / ${mode}`;\n}\n\nexport function providerStatusText(status = providerStatus()) {\n  if (status.ok === false) return status.message || t("provider.not_ready_message");\n  return status.message || t("provider.ready_message");\n}\n\nconst ONBOARDING_STATE_KEYS = {\n  needs_config: "setup.state.needs_config",\n  missing_secrets: "setup.state.missing_secrets",\n  ready: "setup.state.ready",\n};\n\n// Prefer a translated string for known onboarding states; connection failures\n// (provider.ok === false) can carry a live, non-enumerable error detail, so\n// those still fall back to the raw backend message via providerStatusText.\nexport function localizedOnboardingMessage(status = providerStatus()) {\n  if (status.ok === false) return providerStatusText(status);\n  const onboarding = store.state.email_accounts?.onboarding || {};\n  const key = ONBOARDING_STATE_KEYS[onboarding.state];\n  return key ? t(key) : onboarding.message || providerStatusText(status);\n}\n\n// Same idea for the checklist\'s "storage connection" row: enumerable ready\n// states get a translated string, live connection errors keep the raw message.\nexport function connectionStatusText(status = providerStatus()) {\n  if (status.ok === false) return status.message || t("provider.not_ready_message");\n  if (status.provider === "local") return t("setup.local_storage");\n  if (status.provider === "busabase") return t("setup.busabase.connected");\n  return status.message || t("provider.ready_message");\n}\n\nexport function setupState() {\n  return store.state.setup || {};\n}\n';

const KELLY_EMAIL_JS_ROUTER_JS =
  'import { toast } from "./api.js";\nimport { store } from "./store.js";\n\n// closeHelp/openHelp (help-modal.js), refresh/renderList/renderDetail\n// (list-detail.js), and syncModeButtons/isMobileLayout/setMobileDetailOpen\n// (shell.js) all need routing and vice versa. Rather than import across that\n// whole cycle, main.js registers the real implementations once every module\n// has loaded.\nconst hooks = {\n  isHelpOpen: () => false,\n  openHelp: () => {},\n  closeHelp: () => {},\n  activeHelpTab: () => "guide",\n  syncModeButtons: () => {},\n  isMobileLayout: () => false,\n  setMobileDetailOpen: () => {},\n  refresh: async () => {},\n  renderList: () => {},\n  renderDetail: () => {},\n};\n\nexport function registerRouterHooks(overrides) {\n  Object.assign(hooks, overrides);\n}\n\nexport function routeModes() {\n  return ["all", "needs_review", "approved", "done", "blocked"];\n}\n\nexport function helpTabs() {\n  return ["guide", "files", "accounts", "profile", "style", "knowledge", "appearance", "config"];\n}\n\nfunction encodeRoutePart(value) {\n  return encodeURIComponent(String(value || ""));\n}\n\nfunction decodeRoutePart(value) {\n  try {\n    return decodeURIComponent(value || "");\n  } catch {\n    return value || "";\n  }\n}\n\nexport function routeFor() {\n  const modalOpen = hooks.isHelpOpen();\n  if (modalOpen) {\n    const activeTab = hooks.activeHelpTab() || "guide";\n    return `/settings/${activeTab}`;\n  }\n  const modePart = routeModes().includes(store.mode) ? store.mode : "all";\n  return store.selectedId ? `/${modePart}/${encodeRoutePart(store.selectedId)}` : `/${modePart}`;\n}\n\nexport function parseHashRoute() {\n  const raw = (window.location.hash || "").replace(/^#\\/?/, "");\n  const parts = raw.split("/").filter(Boolean).map(decodeRoutePart);\n  if (parts[0] === "settings") {\n    const requestedTab = parts[1] === "language" ? "appearance" : parts[1];\n    return {\n      settingsTab: helpTabs().includes(requestedTab) ? requestedTab : "guide",\n      mode: store.mode,\n      selectedId: store.selectedId,\n    };\n  }\n  return {\n    settingsTab: null,\n    mode: routeModes().includes(parts[0]) ? parts[0] : store.mode,\n    selectedId: parts[1] || null,\n  };\n}\n\nexport function hashHasSelectedMessage() {\n  return Boolean(parseHashRoute().selectedId);\n}\n\nexport function applyRouteFromHash({ refreshData = false } = {}) {\n  store.isApplyingRoute = true;\n  store.routeNeedsReplace = false;\n  const route = parseHashRoute();\n  store.mode = route.mode;\n  store.selectedId = route.selectedId;\n  if (hooks.isMobileLayout()) hooks.setMobileDetailOpen(Boolean(store.selectedId));\n  hooks.syncModeButtons();\n  if (route.settingsTab) {\n    hooks.openHelp(route.settingsTab);\n  } else if (hooks.isHelpOpen()) {\n    hooks.closeHelp({ skipRoute: true });\n  }\n  store.isApplyingRoute = false;\n  if (refreshData) hooks.refresh({ preserveScroll: false }).catch((error) => toast(error.message));\n}\n\nexport function syncRoute({ push = false } = {}) {\n  if (store.isApplyingRoute) {\n    store.routeNeedsReplace = true;\n    return;\n  }\n  const target = `#${routeFor()}`;\n  if (window.location.hash === target) return;\n  if (push) window.location.hash = target;\n  else history.replaceState(null, "", target);\n}\n\nexport function navigateTo(next = {}, { replace = false, refreshData = false } = {}) {\n  if ("mode" in next) store.mode = next.mode;\n  if ("selectedId" in next) store.selectedId = next.selectedId;\n  hooks.syncModeButtons();\n  const target = `#${routeFor()}`;\n  if (window.location.hash === target) {\n    if (refreshData) hooks.refresh({ preserveScroll: false }).catch((error) => toast(error.message));\n    else {\n      hooks.renderList();\n      hooks.renderDetail();\n    }\n    return;\n  }\n  if (replace) {\n    history.replaceState(null, "", target);\n    if (refreshData) hooks.refresh({ preserveScroll: false }).catch((error) => toast(error.message));\n    else {\n      hooks.renderList();\n      hooks.renderDetail();\n    }\n  } else {\n    window.location.hash = target;\n  }\n}\n';

const KELLY_EMAIL_JS_SETUP_JS =
  'import { api, toast } from "./api.js";\nimport { escapeHtml } from "./format.js";\nimport { t } from "./i18n.js";\nimport {\n  connectionStatusText,\n  localizedOnboardingMessage,\n  providerModeLabel,\n  providerStatus,\n  setupNeeded,\n  setupState,\n} from "./provider.js";\nimport { $, store } from "./store.js";\n\n// applyProviderGate/autosaveBusabaseConfig call refresh() (list-detail.js),\n// which in turn calls applyLockState() (shell.js) -> applyProviderGate() —\n// a real cycle. main.js registers the live refresh() once every module is\n// loaded, same pattern as router.js\'s hooks.\nconst hooks = { refresh: async () => {} };\nexport function registerSetupHooks(overrides) {\n  Object.assign(hooks, overrides);\n}\n\nexport function setupPrompt() {\n  const setup = setupState();\n  const status = providerStatus();\n  const connection = status.connection || {};\n  const provider = setup.provider || status.provider || "local";\n  if (!setup.provider_selected) {\n    return t("setup.prompt.choose");\n  }\n  if (provider === "busabase") {\n    return t("setup.prompt.busabase", {\n      config: setup.recommended_config || "busabase:drive/config/config.json",\n      vault: setup.recommended_env || "busabase:vault/kelly-email",\n      baseUrl: status.base_url || connection.base_url || "http://127.0.0.1:15419",\n      baseId: status.base_id || connection.base_id || "kelly-email",\n      apiKeyEnv: connection.api_key === "configured" ? "KELLY_EMAIL_BUSABASE_API_KEY (configured)" : "none",\n    });\n  }\n  return t("setup.prompt.local", {\n    config: setup.recommended_config || "~/.config/kelly-email/config.json",\n    env: setup.recommended_env || "~/.config/kelly-email/.env",\n  });\n}\n\nexport function setupChecklistHtml() {\n  const setup = setupState();\n  const status = providerStatus();\n  const connection = status.connection || {};\n  const onboarding = store.state.email_accounts?.onboarding || {};\n  const providerSelected = Boolean(setup.provider_selected);\n  const busabaseSelected = providerSelected && status.provider === "busabase";\n  const missingSecrets = setup.missing_env || [];\n  const secretsReady = Boolean(onboarding.configured && missingSecrets.length === 0);\n  const providerFirst = t("setup.choose_first");\n  const localStorageLabel = t("setup.local_storage");\n  const rows = [\n    [t("setup.check.provider"), providerSelected, providerModeLabel(status)],\n    [\n      t("setup.check.connection"),\n      providerSelected && status.ok !== false,\n      providerSelected ? connectionStatusText(status) : providerFirst,\n    ],\n    [\n      t("setup.check.folder"),\n      busabaseSelected ? Boolean(connection.folder_exists) : providerSelected,\n      busabaseSelected ? status.folder_slug || "" : providerSelected ? localStorageLabel : providerFirst,\n    ],\n    [\n      t("setup.check.base"),\n      busabaseSelected ? Boolean(connection.base_exists) : providerSelected,\n      busabaseSelected ? status.base_id || "" : providerSelected ? localStorageLabel : providerFirst,\n    ],\n    [\n      t("setup.check.contacts"),\n      busabaseSelected ? Boolean(connection.contacts_base_exists) : providerSelected,\n      busabaseSelected ? status.contacts_base_id || "" : providerSelected ? localStorageLabel : providerFirst,\n    ],\n    [\n      t("setup.check.drive"),\n      busabaseSelected ? Boolean(connection.drive_exists) : providerSelected,\n      busabaseSelected ? status.drive_slug || "" : providerSelected ? localStorageLabel : providerFirst,\n    ],\n    [t("setup.check.config"), Boolean(onboarding.configured), setup.recommended_config || ""],\n    [\n      t("setup.check.secrets"),\n      secretsReady,\n      missingSecrets.length ? missingSecrets.join(", ") : setup.recommended_env || "",\n    ],\n  ];\n  return rows\n    .map(([label, ok, detail]) => {\n      const stateClass = ok ? "ok" : "warn";\n      const stateText = ok ? t("setup.ready") : t("setup.todo");\n      return `\n        <div class="setup-check">\n          <span class="env-pill ${stateClass}">${escapeHtml(stateText)}</span>\n          <strong>${escapeHtml(label)}</strong>\n          <small>${escapeHtml(detail || "")}</small>\n        </div>\n      `;\n    })\n    .join("");\n}\n\nexport async function chooseProvider(provider) {\n  store.forceChooseStep = false;\n  if (provider !== "busabase") store.busabaseFormVisible = false;\n  try {\n    await api("/api/setup/provider", { provider });\n    toast(t("setup.provider_saved", { provider }));\n    await hooks.refresh({ preserveScroll: false });\n  } catch (error) {\n    toast(error.message);\n  }\n}\n\n// The card the user clicks only sets a pending choice — it does not save or\n// navigate. Next is what confirms it, so choosing a provider is a deliberate\n// two-step action instead of a click that immediately commits.\nexport function selectProviderDraft(provider) {\n  store.chooseStepDraft = provider;\n  applyProviderGate();\n}\n\nfunction pendingProviderChoice() {\n  if (store.chooseStepDraft) return store.chooseStepDraft;\n  const setup = setupState();\n  const status = providerStatus();\n  return setup.provider_selected ? setup.provider || status.provider || "local" : "";\n}\n\nexport async function confirmProviderChoice() {\n  const choice = pendingProviderChoice();\n  if (!choice) return;\n  store.chooseStepDraft = null;\n  if (choice === "busabase") {\n    goToBusabaseStep();\n  } else {\n    await chooseProvider("local");\n  }\n}\n\nexport function goToBusabaseStep() {\n  store.forceChooseStep = false;\n  store.busabaseFormVisible = true;\n  applyProviderGate();\n}\n\nexport function backFromBusabaseStep() {\n  store.busabaseFormVisible = false;\n  // Keep Busabase highlighted with Next enabled — the user picked it on\n  // purpose; losing that on Back would make them re-click the card for no\n  // reason when nothing about their choice changed.\n  store.chooseStepDraft = "busabase";\n  applyProviderGate();\n}\n\nconst BUSABASE_HOSTING_DEFAULT_BASE_URL = { cloud: "https://busabase.com", self_hosted: "http://127.0.0.1:15419" };\n\nexport function busabaseHosting() {\n  return document.querySelector("[data-busabase-hosting]:checked")?.value === "cloud" ? "cloud" : "self_hosted";\n}\n\nexport function updateBusabaseFormVisibility() {\n  const hosting = busabaseHosting();\n  const isCloud = hosting === "cloud";\n  $("busabaseSpaceIdRow")?.classList.toggle("is-hidden", !isCloud);\n  $("busabaseApiKeyRow")?.classList.toggle("is-hidden", !isCloud);\n  const baseUrlInput = $("busabaseBaseUrlInput");\n  if (baseUrlInput && document.activeElement !== baseUrlInput) {\n    const current = baseUrlInput.value.trim();\n    const otherDefault = BUSABASE_HOSTING_DEFAULT_BASE_URL[isCloud ? "self_hosted" : "cloud"];\n    // Only swap in the new mode\'s default if the field is empty or still\n    // holds the other mode\'s default — never clobber a value the user typed.\n    if (!current || current === otherDefault) baseUrlInput.value = BUSABASE_HOSTING_DEFAULT_BASE_URL[hosting];\n  }\n}\n\nexport function fillBusabaseForm() {\n  const status = providerStatus();\n  const hosting = status.hosting === "cloud" ? "cloud" : "self_hosted";\n  const hostingInput = document.querySelector(`[data-busabase-hosting][value="${hosting}"]`);\n  if (hostingInput && document.activeElement?.name !== "busabaseHosting") hostingInput.checked = true;\n  const baseUrlInput = $("busabaseBaseUrlInput");\n  if (baseUrlInput && document.activeElement !== baseUrlInput) {\n    baseUrlInput.value = status.base_url || baseUrlInput.value || "";\n  }\n  const spaceIdInput = $("busabaseSpaceIdInput");\n  if (spaceIdInput && document.activeElement !== spaceIdInput) {\n    spaceIdInput.value = status.space_id || spaceIdInput.value || "";\n  }\n  const apiKeyConfigured = status.connection?.api_key === "configured";\n  const apiPill = $("busabaseApiKeyPill");\n  if (apiPill) {\n    apiPill.classList.toggle("ok", apiKeyConfigured);\n    apiPill.classList.toggle("warn", !apiKeyConfigured);\n    apiPill.textContent = apiKeyConfigured ? t("setup.ready") : t("setup.todo");\n  }\n  const apiKeyInput = $("busabaseApiKeyInput");\n  if (apiKeyInput && document.activeElement !== apiKeyInput) {\n    // Never echo the real secret back into the browser; only hint that one\n    // already exists, so leaving this blank on save keeps it unchanged.\n    apiKeyInput.placeholder = apiKeyConfigured\n      ? t("setup.busabase.api_key_placeholder_configured")\n      : t("setup.busabase.api_key_placeholder_empty");\n  }\n  const apiHint = $("busabaseApiKeyHint");\n  if (apiHint) apiHint.textContent = t("setup.busabase.api_key_hint", { env: "KELLY_EMAIL_BUSABASE_API_KEY" });\n  updateBusabaseFormVisibility();\n}\n\nfunction setBusabaseAutosaveStatus(text, kind) {\n  const status = $("busabaseAutosaveStatus");\n  if (!status) return;\n  status.textContent = text;\n  status.classList.toggle("is-saved", kind === "saved");\n  status.classList.toggle("is-error", kind === "error");\n}\n\nexport function scheduleBusabaseAutosave() {\n  clearTimeout(store.busabaseAutosaveTimer);\n  setBusabaseAutosaveStatus("", "");\n  store.busabaseAutosaveTimer = setTimeout(() => autosaveBusabaseConfig(), 700);\n}\n\n// Debounced: fires ~700ms after the user stops typing in any field, and\n// immediately on a hosting-mode change. No manual "Save" button — matches\n// the rest of the app\'s auto-refresh/autosave feel instead of a form submit.\nexport async function autosaveBusabaseConfig() {\n  const hosting = busabaseHosting();\n  const baseUrl = ($("busabaseBaseUrlInput")?.value || "").trim();\n  const spaceId = ($("busabaseSpaceIdInput")?.value || "").trim();\n  const apiKey = ($("busabaseApiKeyInput")?.value || "").trim();\n  if (!baseUrl) {\n    setBusabaseAutosaveStatus(t("setup.busabase.base_url_required"), "error");\n    return false;\n  }\n  if (hosting === "cloud" && !spaceId) {\n    setBusabaseAutosaveStatus(t("setup.busabase.space_id_required"), "error");\n    return false;\n  }\n  const token = ++store.busabaseAutosaveToken;\n  setBusabaseAutosaveStatus(t("setup.busabase.autosave_saving"), "");\n  try {\n    await api("/api/setup/provider", {\n      provider: "busabase",\n      hosting,\n      base_url: baseUrl,\n      space_id: spaceId,\n      api_key: apiKey,\n    });\n    if (token !== store.busabaseAutosaveToken) return true;\n    const apiKeyInput = $("busabaseApiKeyInput");\n    if (apiKeyInput) apiKeyInput.value = "";\n    setBusabaseAutosaveStatus(t("setup.busabase.autosave_saved"), "saved");\n    await hooks.refresh({ preserveScroll: false });\n    return true;\n  } catch (error) {\n    if (token !== store.busabaseAutosaveToken) return false;\n    setBusabaseAutosaveStatus(error.message || t("setup.busabase.autosave_error"), "error");\n    return false;\n  }\n}\n\nexport async function continueFromBusabaseStep() {\n  clearTimeout(store.busabaseAutosaveTimer);\n  const ok = await autosaveBusabaseConfig();\n  if (!ok) return;\n  store.busabaseFormVisible = false;\n  applyProviderGate();\n}\n\nexport async function copySetupPrompt() {\n  const text = setupPrompt();\n  await navigator.clipboard.writeText(text);\n  toast(t("setup.prompt_copied"));\n}\n\n// One step visible at a time, wizard-style, instead of every control on one\n// long scrolling screen: choose a provider -> (Busabase only) connect ->\n// ready. Deliberately derived from existing signals rather than its own\n// persisted field: busabaseFormVisible means "the user is actively looking\n// at the connection step"; forceChooseStep lets a user back out to the\n// provider choice even after one is already saved.\nexport function setupStep() {\n  if (store.busabaseFormVisible) return "configure_busabase";\n  if (store.forceChooseStep) return "choose_provider";\n  return setupState().provider_selected ? "ready" : "choose_provider";\n}\n\nexport function returnToChooseStep() {\n  store.forceChooseStep = true;\n  applyProviderGate();\n}\n\nexport function applyProviderGate() {\n  const unavailable = setupNeeded();\n  const gate = $("providerGate");\n  if (!gate) return;\n  const status = providerStatus();\n  const setup = setupState();\n  gate.classList.toggle("is-hidden", !unavailable);\n  gate.setAttribute("aria-hidden", String(!unavailable));\n\n  const step = setupStep();\n  $("setupStepChoose")?.classList.toggle("is-hidden", step !== "choose_provider");\n  $("setupStepBusabase")?.classList.toggle("is-hidden", step !== "configure_busabase");\n  $("setupStepReady")?.classList.toggle("is-hidden", step !== "ready");\n  $("setupActionsReady")?.classList.toggle("is-hidden", step !== "ready");\n  if (step !== store.lastSetupStep) {\n    store.lastSetupStep = step;\n    // Otherwise a leftover scroll position from a longer step can leave the\n    // next (shorter) step looking blank until the user manually scrolls up.\n    $("providerGateBody")?.scrollTo(0, 0);\n  }\n\n  const message = $("providerGateMessage");\n  if (message) message.textContent = t("setup.choose_provider");\n\n  const activeProvider = setup.provider || status.provider || "local";\n\n  if (step === "configure_busabase") fillBusabaseForm();\n\n  if (step === "ready") {\n    const messageReady = $("providerGateMessageReady");\n    if (messageReady) messageReady.textContent = localizedOnboardingMessage(status);\n    const gateMode = $("providerGateMode");\n    if (gateMode) gateMode.textContent = providerModeLabel(status);\n    const showBusabaseMeta = activeProvider === "busabase";\n    for (const id of [\n      "providerGateBaseUrlLabel",\n      "providerGateBaseUrl",\n      "providerGateBaseIdLabel",\n      "providerGateBaseId",\n    ]) {\n      $(id)?.classList.toggle("is-hidden", !showBusabaseMeta);\n    }\n    const baseUrl = $("providerGateBaseUrl");\n    if (baseUrl) baseUrl.textContent = status.base_url || t("settings.not_configured");\n    const baseId = $("providerGateBaseId");\n    if (baseId) baseId.textContent = status.base_id || t("settings.not_configured");\n    const action = $("providerGateAction");\n    if (action) action.textContent = status.action || t("setup.next_action");\n    const checklist = $("setupChecklist");\n    if (checklist) checklist.innerHTML = setupChecklistHtml();\n    const prompt = $("setupPromptText");\n    if (prompt) prompt.textContent = setupPrompt();\n    const promptTitle = $("setupPromptTitle");\n    if (promptTitle) promptTitle.textContent = t("setup.prompt_title.provider", { provider: activeProvider });\n    const reconfigure = $("busabaseReconfigureButton");\n    if (reconfigure) reconfigure.classList.toggle("is-hidden", activeProvider !== "busabase");\n  }\n\n  const localButton = $("setupChooseLocal");\n  const busabaseButton = $("setupChooseBusabase");\n  const currentChoice = step === "configure_busabase" ? "busabase" : pendingProviderChoice();\n  for (const button of [localButton, busabaseButton]) {\n    if (!button) continue;\n    button.classList.toggle("active", button.dataset.providerChoice === currentChoice);\n    button.disabled = Boolean(setup.provider_env_locked);\n  }\n  const nextButton = $("setupChooseNextButton");\n  if (nextButton) nextButton.disabled = !pendingProviderChoice() || Boolean(setup.provider_env_locked);\n  const busabaseForm = $("busabaseConfigForm");\n  if (busabaseForm) {\n    busabaseForm.querySelectorAll("input, button").forEach((node) => {\n      node.disabled = Boolean(setup.provider_env_locked);\n    });\n  }\n}\n';

const KELLY_EMAIL_JS_SHELL_JS =
  'import { api } from "./api.js";\nimport { t } from "./i18n.js";\nimport { setupNeeded } from "./provider.js";\nimport { applyProviderGate } from "./setup.js";\nimport { $, SIDEBAR_COLLAPSED_STORAGE_KEY, store } from "./store.js";\n\nexport function isMobileLayout() {\n  return window.matchMedia("(max-width: 720px)").matches;\n}\n\nexport function syncModeButtons() {\n  document.querySelectorAll("[data-mode]").forEach((node) => {\n    node.classList.toggle("active", node.dataset.mode === store.mode);\n  });\n}\n\nfunction syncSidebarState() {\n  const collapsed = document.body.classList.contains("sidebar-collapsed");\n  const toggle = $("sidebarToggle");\n  if (toggle) toggle.setAttribute("aria-expanded", String(!collapsed));\n}\n\nexport function setSidebarCollapsed(collapsed, { persist = true } = {}) {\n  document.body.classList.toggle("sidebar-collapsed", collapsed);\n  syncSidebarState();\n  if (persist) localStorage.setItem(SIDEBAR_COLLAPSED_STORAGE_KEY, collapsed ? "1" : "0");\n}\n\nexport function setMobileSidebarOpen(open) {\n  document.body.classList.toggle("sidebar-open", open);\n  const scrim = $("sidebarScrim");\n  if (scrim) scrim.hidden = !open;\n}\n\nexport function toggleSidebar() {\n  if (isMobileLayout()) {\n    setMobileSidebarOpen(!document.body.classList.contains("sidebar-open"));\n    return;\n  }\n  setSidebarCollapsed(!document.body.classList.contains("sidebar-collapsed"));\n}\n\nexport function setMobileDetailOpen(open) {\n  store.mobileDetailOpen = Boolean(open);\n  document.body.classList.toggle("mobile-detail-open", store.mobileDetailOpen);\n}\n\nexport function syncResponsiveShell() {\n  if (isMobileLayout()) {\n    document.body.classList.remove("sidebar-collapsed");\n    setMobileSidebarOpen(false);\n    setMobileDetailOpen(Boolean(store.selectedId) && store.mobileDetailOpen);\n  } else {\n    setMobileSidebarOpen(false);\n    setMobileDetailOpen(false);\n    setSidebarCollapsed(localStorage.getItem(SIDEBAR_COLLAPSED_STORAGE_KEY) === "1", { persist: false });\n  }\n  syncSidebarState();\n}\n\nexport function closeDetailActionMenu() {\n  store.openActionMenu = false;\n  const menu = $("detailActionMenu");\n  const toggle = $("detailActionMenuToggle");\n  if (menu) menu.classList.remove("is-open");\n  if (toggle) toggle.setAttribute("aria-expanded", "false");\n}\n\nexport function resizeHtmlPreviewFrame(frame) {\n  if (!frame) return;\n  const minHeight = 180;\n  const maxHeight = 2000;\n  try {\n    const doc = frame.contentDocument || frame.contentWindow?.document;\n    if (!doc) return;\n    const body = doc.body;\n    const root = doc.documentElement;\n    const height = Math.max(\n      body?.scrollHeight || 0,\n      body?.offsetHeight || 0,\n      root?.scrollHeight || 0,\n      root?.offsetHeight || 0,\n      minHeight,\n    );\n    const nextHeight = Math.min(height + 2, maxHeight);\n    frame.style.height = `${nextHeight}px`;\n    frame.classList.toggle("is-clamped", height > maxHeight);\n  } catch {\n    frame.style.height = "720px";\n  }\n}\n\nexport function attachHtmlPreviewAutoResize() {\n  const frame = document.querySelector(".html-preview");\n  if (!frame) return;\n  const resize = () => resizeHtmlPreviewFrame(frame);\n  frame.addEventListener(\n    "load",\n    () => {\n      resize();\n      setTimeout(resize, 80);\n      setTimeout(resize, 400);\n    },\n    { once: true },\n  );\n  requestAnimationFrame(resize);\n}\n\nexport function isEditing() {\n  const active = document.activeElement;\n  if (!active) return false;\n  if (active.matches("textarea")) return true;\n  return active.matches("input") && active.id !== "searchInput";\n}\n\nexport function captureScrollState() {\n  const page = document.scrollingElement || document.documentElement;\n  return {\n    pageTop: page?.scrollTop || 0,\n    listTop: $("messageList")?.scrollTop || 0,\n    detailTop: $("detailPanel")?.scrollTop || 0,\n  };\n}\n\nexport function restoreScrollState(scrollState) {\n  const page = document.scrollingElement || document.documentElement;\n  if (page) page.scrollTop = scrollState.pageTop;\n  const list = $("messageList");\n  if (list) list.scrollTop = scrollState.listTop;\n  const detail = $("detailPanel");\n  if (detail) detail.scrollTop = scrollState.detailTop;\n}\n\nexport function isLocked() {\n  return Boolean(store.state.lock?.locked);\n}\n\nexport function applyLockState() {\n  const locked = isLocked();\n  const unavailable = setupNeeded();\n  document.body.classList.toggle("is-locked", locked);\n  document.body.classList.toggle("provider-unavailable", unavailable);\n  if (locked || unavailable) closeDetailActionMenu();\n  applyProviderGate();\n  const banner = $("lockBanner");\n  if (banner) {\n    banner.classList.toggle("is-hidden", !locked);\n  }\n  const message = $("lockMessage");\n  if (message) {\n    message.textContent = locked ? store.state.lock.message || t("lock.processing") : t("lock.default");\n  }\n  document.querySelectorAll("button, input, textarea, select").forEach((node) => {\n    const keepEnabled =\n      node.id === "searchInput" ||\n      node.id === "helpButton" ||\n      node.id === "mobileHelpButton" ||\n      node.id === "providerGateHelpButton" ||\n      node.id === "setupChooseLocal" ||\n      node.id === "setupChooseBusabase" ||\n      node.id === "busabaseBackButton" ||\n      node.id === "busabaseContinueButton" ||\n      node.id === "busabaseReconfigureButton" ||\n      node.id === "setupChangeProviderButton" ||\n      node.id === "setupCopyPrompt" ||\n      node.id === "closeHelp" ||\n      node.id === "sidebarToggle" ||\n      node.id === "mobileSidebarToggle" ||\n      Boolean(node.closest("#helpModal")) ||\n      Boolean(node.closest("#busabaseConfigForm"));\n    node.disabled = !keepEnabled && (locked || unavailable);\n  });\n}\n\nexport async function pollLock() {\n  const data = await api("/api/lock");\n  store.state.lock = data.lock || { locked: false };\n  applyLockState();\n}\n';

const KELLY_EMAIL_JS_STORE_JS =
  '// Shared mutable app state. One object, not many exported `let` bindings —\n// ESM only gives importers a read-only live view of an exported `let`, so\n// every reassignment would need its own setter function. Mutating properties\n// of a shared object works the same way across every module that imports it.\n\nexport const $ = (id) => document.getElementById(id);\n\nconst ACCENT_THEMES = [\n  { id: "blue", color: "#0a84ff" },\n  { id: "purple", color: "#bf5af2" },\n  { id: "pink", color: "#ff2d55" },\n  { id: "red", color: "#ff3b30" },\n  { id: "orange", color: "#ff9500" },\n  { id: "yellow", color: "#ffcc00", check: "#1d1d1f" },\n  { id: "green", color: "#30d158" },\n  { id: "graphite", color: "#6e6e73" },\n];\n\nconst LANGUAGE_OPTIONS = [\n  { value: "auto", labelKey: "language.auto" },\n  { value: "en", labelKey: "language.english" },\n  { value: "zh-CN", labelKey: "language.chinese" },\n];\n\nexport const LANGUAGE_STORAGE_KEY = "kelly-email.uiLanguage";\nexport const ACCENT_THEME_STORAGE_KEY = "kelly-email.accentTheme";\nexport const SIDEBAR_COLLAPSED_STORAGE_KEY = "kelly-email.sidebarCollapsed";\nexport { ACCENT_THEMES, LANGUAGE_OPTIONS };\n\nexport function resolveAccentTheme(value) {\n  return ACCENT_THEMES.some((theme) => theme.id === value) ? value : "blue";\n}\n\nfunction modeForDemo(value) {\n  if (["review", "needs-review", "needs_review", "needs"].includes(value)) return "needs_review";\n  if (["approved", "blocked", "done"].includes(value)) return value;\n  return "all";\n}\n\nconst params = new URLSearchParams(window.location.search);\nconst demoScenario = params.get("demo") || "";\nconst queryLanguage = params.get("lang");\n\nexport const store = {\n  params,\n  state: { items: [], counts: {}, batch: null, lock: { locked: false } },\n  selectedId: null,\n  checked: new Set(),\n  refreshTimer: null,\n  lockTimer: null,\n  busabaseFormVisible: false,\n  // Lets a user back out to the provider choice even after one is already\n  // saved — otherwise the only way back is deleting the local config file.\n  forceChooseStep: false,\n  // The card the user just clicked on the choose-provider step, before they\n  // confirm it with Next — null falls back to whatever provider is already\n  // saved, so returning to this step re-highlights the current choice.\n  chooseStepDraft: null,\n  mode: modeForDemo(demoScenario),\n  languageMode: queryLanguage || localStorage.getItem(LANGUAGE_STORAGE_KEY) || "auto",\n  accentTheme: resolveAccentTheme(localStorage.getItem(ACCENT_THEME_STORAGE_KEY) || "blue"),\n  uiLanguage: "en",\n  isApplyingRoute: false,\n  routeNeedsReplace: false,\n  openActionMenu: false,\n  mobileDetailOpen: false,\n  lastSetupStep: "",\n  busabaseAutosaveTimer: null,\n  busabaseAutosaveToken: 0,\n};\n';

const KELLY_EMAIL_STYLES_BASE_CSS =
  '@layer base {\n  :root {\n    color-scheme: light;\n    --bg: #f7f8fa;\n    --panel: #ffffff;\n    --panel-subtle: #fafbfc;\n    --line: #e5e7eb;\n    --line-strong: #d8dde6;\n    --text: #171a1f;\n    --muted: #6b7280;\n    --muted-soft: #9aa3af;\n    --accent: #0a84ff;\n    --accent-strong: #0071e3;\n    --accent-soft: rgba(10, 132, 255, 0.08);\n    --accent-wash: rgba(10, 132, 255, 0.045);\n    --accent-line: rgba(10, 132, 255, 0.26);\n    --accent-focus: rgba(10, 132, 255, 0.2);\n    --accent-text: #0066cc;\n    --accent-contrast: #ffffff;\n    --danger: #b42318;\n    --danger-soft: #fff1f0;\n    --warning: #9a6700;\n    --warning-soft: #fff8db;\n    --ok: #047857;\n    --ok-soft: #ecfdf3;\n    --shadow: 0 1px 2px rgba(16, 24, 40, 0.04);\n  }\n\n  html[data-accent-theme="purple"] {\n    --accent: #bf5af2;\n    --accent-strong: #9f35d0;\n    --accent-soft: rgba(191, 90, 242, 0.09);\n    --accent-wash: rgba(191, 90, 242, 0.045);\n    --accent-line: rgba(191, 90, 242, 0.28);\n    --accent-focus: rgba(191, 90, 242, 0.2);\n    --accent-text: #8f2bbf;\n    --accent-contrast: #ffffff;\n  }\n\n  html[data-accent-theme="pink"] {\n    --accent: #ff2d55;\n    --accent-strong: #e11d48;\n    --accent-soft: rgba(255, 45, 85, 0.085);\n    --accent-wash: rgba(255, 45, 85, 0.045);\n    --accent-line: rgba(255, 45, 85, 0.26);\n    --accent-focus: rgba(255, 45, 85, 0.18);\n    --accent-text: #c9163d;\n    --accent-contrast: #ffffff;\n  }\n\n  html[data-accent-theme="red"] {\n    --accent: #ff3b30;\n    --accent-strong: #d92d24;\n    --accent-soft: rgba(255, 59, 48, 0.085);\n    --accent-wash: rgba(255, 59, 48, 0.045);\n    --accent-line: rgba(255, 59, 48, 0.26);\n    --accent-focus: rgba(255, 59, 48, 0.18);\n    --accent-text: #c1261e;\n    --accent-contrast: #ffffff;\n  }\n\n  html[data-accent-theme="orange"] {\n    --accent: #ff9500;\n    --accent-strong: #a65300;\n    --accent-soft: rgba(255, 149, 0, 0.1);\n    --accent-wash: rgba(255, 149, 0, 0.052);\n    --accent-line: rgba(255, 149, 0, 0.28);\n    --accent-focus: rgba(255, 149, 0, 0.2);\n    --accent-text: #a65300;\n    --accent-contrast: #ffffff;\n  }\n\n  html[data-accent-theme="yellow"] {\n    --accent: #c78b00;\n    --accent-strong: #7a5200;\n    --accent-soft: rgba(255, 204, 0, 0.14);\n    --accent-wash: rgba(255, 204, 0, 0.07);\n    --accent-line: rgba(199, 139, 0, 0.3);\n    --accent-focus: rgba(199, 139, 0, 0.2);\n    --accent-text: #7a5200;\n    --accent-contrast: #ffffff;\n  }\n\n  html[data-accent-theme="green"] {\n    --accent: #30d158;\n    --accent-strong: #147a32;\n    --accent-soft: rgba(48, 209, 88, 0.105);\n    --accent-wash: rgba(48, 209, 88, 0.052);\n    --accent-line: rgba(48, 209, 88, 0.3);\n    --accent-focus: rgba(48, 209, 88, 0.22);\n    --accent-text: #147a32;\n    --accent-contrast: #ffffff;\n  }\n\n  html[data-accent-theme="graphite"] {\n    --accent: #6e6e73;\n    --accent-strong: #5b5b60;\n    --accent-soft: rgba(110, 110, 115, 0.095);\n    --accent-wash: rgba(110, 110, 115, 0.045);\n    --accent-line: rgba(110, 110, 115, 0.26);\n    --accent-focus: rgba(110, 110, 115, 0.18);\n    --accent-text: #4b4b50;\n    --accent-contrast: #ffffff;\n  }\n\n  * {\n    box-sizing: border-box;\n  }\n\n  html,\n  body {\n    height: 100%;\n    overflow: hidden;\n  }\n\n  body {\n    margin: 0;\n    font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\n    background: var(--bg);\n    color: var(--text);\n    letter-spacing: 0;\n    font-size: 14px;\n  }\n\n  button,\n  input,\n  textarea {\n    font: inherit;\n  }\n\n  input[type="checkbox"],\n  input[type="radio"] {\n    accent-color: var(--accent);\n  }\n\n  @media (max-width: 720px) {\n    html,\n    body {\n      height: 100%;\n      overflow: hidden;\n    }\n\n    body {\n      font-size: 13px;\n    }\n  }\n}\n';

const KELLY_EMAIL_STYLES_COMPONENTS_CSS =
  '@layer components {\n  button {\n    border: 1px solid var(--line);\n    background: var(--panel);\n    color: var(--text);\n    border-radius: 6px;\n    padding: 7px 11px;\n    cursor: pointer;\n    font-size: 13px;\n    line-height: 1.15;\n    box-shadow: var(--shadow);\n    transition: background 0.12s ease, border-color 0.12s ease, color 0.12s ease, box-shadow 0.12s ease;\n  }\n\n  button:hover {\n    border-color: var(--line-strong);\n    background: #fbfbfc;\n    box-shadow: 0 1px 3px rgba(16, 24, 40, 0.08);\n  }\n\n  button:active {\n    transform: translateY(1px);\n  }\n\n  button:disabled,\n  input:disabled,\n  textarea:disabled {\n    cursor: not-allowed;\n    opacity: 0.55;\n  }\n\n  button.has-tooltip {\n    position: relative;\n  }\n\n  button.has-tooltip::after,\n  button.has-tooltip::before {\n    position: absolute;\n    left: 50%;\n    opacity: 0;\n    pointer-events: none;\n    transform: translate(-50%, 6px);\n    transition: opacity 0.12s ease, transform 0.12s ease;\n    z-index: 20;\n  }\n\n  button.has-tooltip::after {\n    content: attr(data-tooltip);\n    top: calc(100% + 8px);\n    width: max-content;\n    max-width: min(360px, 70vw);\n    white-space: normal;\n    background: #111827;\n    color: #fff;\n    border-radius: 6px;\n    padding: 8px 10px;\n    font-size: 12px;\n    line-height: 1.38;\n    text-align: left;\n    box-shadow: 0 10px 28px rgba(17, 24, 39, 0.24);\n  }\n\n  button.has-tooltip::before {\n    content: "";\n    top: calc(100% + 3px);\n    border: 6px solid transparent;\n    border-bottom-color: #111827;\n  }\n\n  button.has-tooltip:hover::after,\n  button.has-tooltip:hover::before,\n  button.has-tooltip:focus-visible::after,\n  button.has-tooltip:focus-visible::before {\n    opacity: 1;\n    transform: translate(-50%, 0);\n  }\n\n  button.primary {\n    background: linear-gradient(180deg, color-mix(in srgb, var(--accent-strong) 88%, #ffffff), var(--accent-strong));\n    border-color: var(--accent-strong);\n    color: var(--accent-contrast);\n    box-shadow: 0 1px 1px rgba(15, 23, 42, 0.1), inset 0 1px 0 rgba(255, 255, 255, 0.22);\n  }\n\n  button.primary:hover {\n    background: linear-gradient(\n      180deg,\n      color-mix(in srgb, var(--accent-strong) 94%, #ffffff),\n      color-mix(in srgb, var(--accent-strong) 88%, #000000)\n    );\n    border-color: var(--accent-strong);\n  }\n\n  button.danger {\n    color: var(--danger);\n  }\n\n  /* Generic visibility utility. Components with their own hide/show transition\n   (e.g. .provider-gate, .modal-backdrop) keep their own higher-specificity\n   rule; this is the default for anything else toggled with classList. */\n\n  .is-hidden {\n    display: none;\n  }\n\n  .brand-subtitle,\n  .muted {\n    color: var(--muted);\n    font-size: 12px;\n    line-height: 1.45;\n    word-break: break-word;\n  }\n\n  .onboarding-card {\n    margin: 14px;\n    border: 1px solid var(--accent-line);\n    border-radius: 8px;\n    background: var(--accent-wash);\n    padding: 14px;\n    color: #263142;\n  }\n\n  .onboarding-card.compact {\n    margin: 0;\n  }\n\n  .onboarding-card strong {\n    display: block;\n    margin-bottom: 6px;\n    font-size: 14px;\n  }\n\n  .onboarding-card p {\n    margin: 0 0 10px;\n    color: #4b5563;\n    line-height: 1.48;\n  }\n\n  .onboarding-card ol {\n    margin: 0 0 10px;\n    padding-left: 20px;\n    color: #4b5563;\n    line-height: 1.55;\n  }\n\n  .onboarding-card code {\n    overflow-wrap: anywhere;\n  }\n\n  .help-paths {\n    display: grid;\n    grid-template-columns: 110px minmax(0, 1fr);\n    gap: 8px 12px;\n    margin: 0;\n  }\n\n  .help-paths dt {\n    color: var(--muted);\n    font-size: 12px;\n  }\n\n  .help-paths dd {\n    margin: 0;\n    min-width: 0;\n  }\n\n  .help-paths code {\n    display: block;\n    overflow: hidden;\n    text-overflow: ellipsis;\n    white-space: nowrap;\n    color: #374151;\n    font-size: 12px;\n  }\n\n  .language-options label,\n  .theme-option {\n    display: flex;\n    align-items: center;\n    gap: 7px;\n    border: 1px solid var(--line);\n    border-radius: 8px;\n    background: var(--panel);\n    padding: 8px 10px;\n    color: #374151;\n    font-size: 13px;\n    box-shadow: var(--shadow);\n    cursor: pointer;\n    user-select: none;\n  }\n\n  .language-options input,\n  .theme-option input {\n    margin: 0;\n  }\n\n  .theme-options {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(78px, 1fr));\n    gap: 8px;\n  }\n\n  .theme-option {\n    position: relative;\n    min-width: 0;\n    justify-content: center;\n    flex-direction: column;\n    gap: 6px;\n    min-height: 68px;\n    padding: 9px 6px 7px;\n    cursor: pointer;\n    color: var(--muted);\n    font-size: 12px;\n    font-weight: 560;\n    text-align: center;\n    transition: background 0.12s ease, border-color 0.12s ease, box-shadow 0.12s ease;\n  }\n\n  .theme-option input {\n    position: absolute;\n    width: 1px;\n    height: 1px;\n    opacity: 0;\n    pointer-events: none;\n  }\n\n  .theme-option:has(input:checked) {\n    border-color: var(--accent-line);\n    background: var(--accent-wash);\n    color: var(--text);\n    box-shadow: 0 0 0 3px var(--accent-soft), inset 0 1px 0 rgba(255, 255, 255, 0.62);\n  }\n\n  .theme-option:has(input:focus-visible) {\n    outline: 3px solid var(--accent-focus);\n    outline-offset: 2px;\n  }\n\n  .theme-swatch {\n    position: relative;\n    width: 26px;\n    height: 26px;\n    flex: 0 0 auto;\n    border: 1px solid rgba(15, 23, 42, 0.16);\n    border-radius: 999px;\n    background: var(--swatch);\n    box-shadow: inset 0 1px 1px rgba(255, 255, 255, 0.46), inset 0 -1px 1px rgba(0, 0, 0, 0.12);\n  }\n\n  .theme-option:has(input:checked) .theme-swatch {\n    box-shadow: 0 0 0 3px var(--panel), 0 0 0 5px var(--accent), inset 0 1px 1px rgba(255, 255, 255, 0.46), inset 0 -1px\n      1px rgba(0, 0, 0, 0.12);\n  }\n\n  .theme-option:has(input:checked) .theme-swatch::after {\n    content: "";\n    position: absolute;\n    left: 8px;\n    top: 6px;\n    width: 8px;\n    height: 5px;\n    border: 2px solid var(--swatch-check);\n    border-top: 0;\n    border-right: 0;\n    transform: rotate(-45deg);\n  }\n\n  .account-envs,\n  .alias-list {\n    display: flex;\n    flex-wrap: wrap;\n    gap: 5px;\n  }\n\n  .env-pill,\n  .alias-list span {\n    border: 1px solid var(--line);\n    border-radius: 999px;\n    padding: 2px 7px;\n    font-size: 11px;\n    color: #4b5563;\n    background: var(--panel-subtle);\n  }\n\n  .env-pill.ok {\n    color: var(--ok);\n    border-color: #bbf7d0;\n    background: var(--ok-soft);\n  }\n\n  .env-pill.warn {\n    color: var(--warning);\n    border-color: #fde68a;\n    background: var(--warning-soft);\n  }\n\n  .toast {\n    position: fixed;\n    right: 18px;\n    bottom: 18px;\n    background: #111827;\n    color: #fff;\n    border-radius: 8px;\n    padding: 10px 12px;\n    max-width: 420px;\n    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.18);\n  }\n\n  @media (max-width: 720px) {\n    button.has-tooltip::before,\n    button.has-tooltip::after {\n      display: none;\n    }\n\n    .help-paths {\n      grid-template-columns: 1fr;\n    }\n\n    .help-paths {\n      gap: 4px 0;\n    }\n\n    .help-paths dt {\n      margin-top: 8px;\n    }\n\n    .help-paths code {\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n\n    .toast {\n      left: 12px;\n      right: 12px;\n      bottom: 12px;\n      max-width: none;\n    }\n  }\n\n  .onboarding-card,\n  .html-frame {\n    box-shadow: none;\n  }\n}\n';

const KELLY_EMAIL_STYLES_HELP_MODAL_CSS =
  '@layer help-modal {\n  .modal-backdrop {\n    position: fixed;\n    inset: 0;\n    z-index: 100;\n    display: grid;\n    place-items: center;\n    padding: 24px;\n    background: rgba(17, 24, 39, 0.36);\n    backdrop-filter: blur(4px);\n  }\n\n  .modal-backdrop.is-hidden {\n    display: none;\n  }\n\n  .modal {\n    width: min(780px, 100%);\n    max-height: min(760px, calc(100vh - 48px));\n    display: grid;\n    grid-template-rows: auto auto minmax(0, 1fr);\n    overflow: hidden;\n    border: 1px solid var(--line);\n    border-radius: 10px;\n    background: var(--panel);\n    box-shadow: 0 24px 80px rgba(17, 24, 39, 0.28);\n  }\n\n  .modal-head {\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    gap: 16px;\n    padding: 16px 18px;\n    border-bottom: 1px solid var(--line);\n  }\n\n  .modal-title {\n    font-size: 16px;\n    font-weight: 700;\n  }\n\n  .modal-subtitle {\n    margin-top: 3px;\n    color: var(--muted);\n    font-size: 12px;\n  }\n\n  .icon-button {\n    box-shadow: none;\n  }\n\n  .modal-tabs {\n    display: flex;\n    gap: 4px;\n    padding: 10px 14px 0;\n    border-bottom: 1px solid var(--line);\n    background: #fbfcfd;\n  }\n\n  .modal-tabs button {\n    border: 0;\n    border-bottom: 2px solid transparent;\n    border-radius: 0;\n    background: transparent;\n    box-shadow: none;\n    color: var(--muted);\n    padding: 9px 10px 10px;\n    font-weight: 560;\n  }\n\n  .modal-tabs button:hover {\n    background: transparent;\n    color: var(--text);\n    box-shadow: none;\n  }\n\n  .modal-tabs button.active {\n    border-bottom-color: var(--accent);\n    color: var(--text);\n  }\n\n  .modal-body {\n    padding: 18px;\n    overflow: auto;\n  }\n\n  .help-tab-panel {\n    display: none;\n  }\n\n  .help-tab-panel.active {\n    display: grid;\n    gap: 8px;\n  }\n\n  .help-tab-panel ol {\n    margin: 0;\n    padding-left: 19px;\n    color: #4b5563;\n    line-height: 1.55;\n  }\n\n  .modal-body h2 {\n    margin: 0;\n    font-size: 13px;\n    font-weight: 680;\n    color: #374151;\n  }\n\n  .modal-body p {\n    margin: 0;\n    color: #4b5563;\n    line-height: 1.5;\n  }\n\n  .modal-body code,\n  .modal-body pre {\n    font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;\n  }\n\n  .modal-body pre {\n    margin: 0;\n    overflow: auto;\n    border: 1px solid var(--line);\n    border-radius: 8px;\n    background: var(--panel-subtle);\n    padding: 10px;\n    color: #374151;\n    font-size: 12px;\n    line-height: 1.45;\n  }\n\n  .help-accounts {\n    display: grid;\n    gap: 8px;\n  }\n\n  .account-help-card {\n    display: grid;\n    gap: 10px;\n    border: 1px solid var(--accent-line);\n    border-radius: 8px;\n    background: var(--accent-wash);\n    padding: 12px;\n  }\n\n  .account-help-card strong {\n    display: block;\n    font-size: 13px;\n    color: #1f2937;\n  }\n\n  .account-help-card p {\n    margin: 3px 0 0;\n    color: var(--muted);\n    font-size: 12px;\n    line-height: 1.45;\n  }\n\n  .account-help-card pre {\n    margin: 0;\n    overflow: auto;\n    border: 1px solid var(--accent-line);\n    border-radius: 7px;\n    background: #fff;\n    padding: 10px;\n    color: #334155;\n    font-size: 12px;\n    line-height: 1.5;\n    white-space: pre-wrap;\n  }\n\n  .settings-grid {\n    display: grid;\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n    gap: 10px;\n  }\n\n  .settings-card {\n    display: grid;\n    gap: 8px;\n    min-width: 0;\n    border: 1px solid var(--line);\n    border-radius: 8px;\n    background: var(--panel);\n    padding: 10px;\n  }\n\n  .settings-card-title {\n    display: flex;\n    gap: 8px;\n    align-items: center;\n    justify-content: space-between;\n    min-width: 0;\n    font-size: 13px;\n    font-weight: 660;\n    color: var(--text);\n  }\n\n  .settings-card p {\n    color: #4b5563;\n    font-size: 12px;\n    line-height: 1.5;\n  }\n\n  .language-options {\n    display: flex;\n    flex-wrap: wrap;\n    gap: 8px;\n  }\n\n  .settings-row {\n    display: grid;\n    grid-template-columns: 88px minmax(0, 1fr);\n    gap: 8px;\n    align-items: baseline;\n    min-width: 0;\n    color: var(--muted);\n    font-size: 12px;\n  }\n\n  .settings-row strong,\n  .settings-row a,\n  .settings-row code {\n    min-width: 0;\n    overflow: hidden;\n    color: #374151;\n    text-overflow: ellipsis;\n    white-space: nowrap;\n  }\n\n  .settings-row a {\n    color: var(--accent);\n    text-decoration: none;\n  }\n\n  .settings-list,\n  .settings-bullets,\n  .settings-pill-row {\n    display: grid;\n    gap: 6px;\n    min-width: 0;\n  }\n\n  .settings-bullets div {\n    position: relative;\n    padding-left: 12px;\n    color: #4b5563;\n    font-size: 12px;\n    line-height: 1.45;\n  }\n\n  .settings-bullets div::before {\n    content: "";\n    position: absolute;\n    left: 0;\n    top: 0.65em;\n    width: 4px;\n    height: 4px;\n    border-radius: 999px;\n    background: var(--muted-soft);\n  }\n\n  .settings-pill-row {\n    display: flex;\n    flex-wrap: wrap;\n  }\n\n  .settings-pill,\n  .source-type {\n    width: fit-content;\n    border: 1px solid var(--line);\n    border-radius: 999px;\n    background: var(--panel-subtle);\n    color: #4b5563;\n    padding: 2px 7px;\n    font-size: 11px;\n    line-height: 1.45;\n  }\n\n  .source-type {\n    flex: 0 0 auto;\n    text-transform: uppercase;\n    letter-spacing: 0;\n  }\n\n  .account-card {\n    border: 1px solid var(--line);\n    border-radius: 8px;\n    background: var(--panel);\n    overflow: hidden;\n  }\n\n  .account-card-head {\n    display: grid;\n    grid-template-columns: minmax(0, 1fr) auto;\n    gap: 12px;\n    align-items: start;\n    padding: 10px;\n  }\n\n  .account-card strong,\n  .account-card small,\n  .account-row code,\n  .account-identity code {\n    overflow: hidden;\n    text-overflow: ellipsis;\n    white-space: nowrap;\n  }\n\n  .account-card strong {\n    display: block;\n    font-size: 13px;\n    font-weight: 650;\n    color: var(--text);\n  }\n\n  .account-card small {\n    display: block;\n    margin-top: 2px;\n    color: var(--muted);\n    font-size: 12px;\n  }\n\n  .account-detail {\n    border-top: 1px solid var(--line);\n    padding: 8px;\n    display: grid;\n    gap: 7px;\n  }\n\n  .account-row {\n    display: grid;\n    grid-template-columns: 58px 1fr;\n    gap: 6px;\n    align-items: center;\n    font-size: 12px;\n    color: var(--muted);\n  }\n\n  .account-row code,\n  .account-identity code {\n    font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;\n    font-size: 12px;\n    color: #374151;\n  }\n\n  .identity-list {\n    display: grid;\n    gap: 5px;\n  }\n\n  .account-identity {\n    display: grid;\n    gap: 1px;\n    font-size: 11px;\n  }\n\n  .account-identity span {\n    color: #374151;\n    font-weight: 560;\n  }\n\n  @media (max-width: 720px) {\n    .modal-backdrop {\n      padding: 0;\n      align-items: stretch;\n    }\n\n    .modal {\n      width: 100%;\n      height: 100dvh;\n      max-height: 100dvh;\n      border-width: 0;\n      border-radius: 0;\n    }\n\n    .modal-head {\n      align-items: flex-start;\n      gap: 10px;\n      padding: 12px 14px;\n    }\n\n    .modal-head > div {\n      min-width: 0;\n    }\n\n    .modal-title,\n    .modal-subtitle {\n      overflow-wrap: anywhere;\n    }\n\n    .modal-head .icon-button {\n      flex: 0 0 auto;\n      padding: 7px 9px;\n    }\n\n    .modal-tabs {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: 6px;\n      overflow: visible;\n      padding: 10px;\n    }\n\n    .modal-tabs button {\n      min-width: 0;\n      border: 1px solid var(--line);\n      border-radius: 7px;\n      background: #fff;\n      padding: 7px 8px;\n      overflow: hidden;\n      text-overflow: ellipsis;\n      white-space: nowrap;\n      text-align: center;\n    }\n\n    .modal-tabs button:hover {\n      background: #fbfbfc;\n    }\n\n    .modal-tabs button.active {\n      border-color: var(--accent-line);\n      background: var(--accent-soft);\n      color: var(--text);\n    }\n\n    .modal-body {\n      min-width: 0;\n      padding: 14px;\n    }\n\n    .settings-grid,\n    .account-card-head,\n    .settings-row,\n    .account-row {\n      grid-template-columns: 1fr;\n    }\n\n    .settings-row strong,\n    .settings-row a,\n    .settings-row code,\n    .account-card strong,\n    .account-card small,\n    .account-row code,\n    .account-identity code,\n    .modal-body pre,\n    .modal-body code {\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n\n    .modal-body pre {\n      max-width: 100%;\n    }\n  }\n\n  .account-card,\n  .settings-card {\n    box-shadow: none;\n  }\n}\n';

